import React, { useState, useRef, useEffect } from 'react';
import { AppText } from '../types';

interface AudioRecorderProps {
  onAnalyze: (audioBase64: string, duration: number, mimeType: string) => void;
  isAnalyzing: boolean;
  onBack: () => void;
  text: AppText;
}

const AudioRecorder: React.FC<AudioRecorderProps> = ({ onAnalyze, isAnalyzing, onBack, text }) => {
  const [recording, setRecording] = useState(false);
  const [timer, setTimer] = useState(0);
  const [error, setError] = useState<string | null>(null);
  const timerRef = useRef(0);

  // Audio Visualization State
  const [visualizerData, setVisualizerData] = useState<number[]>(new Array(30).fill(5));

  // Analysis Progress State
  const [analysisProgress, setAnalysisProgress] = useState(0);
  const [statusMessage, setStatusMessage] = useState<string>("");

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const timerIntervalRef = useRef<number | null>(null);
  const chunksRef = useRef<Blob[]>([]);

  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const sourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const animationFrameRef = useRef<number | null>(null);

  // Store the active mime type for the current session
  const activeMimeTypeRef = useRef<string>("");

  const MAX_RECORDING_TIME = 600; // 10 minutes
  const WARNING_TIME = 540; 

  useEffect(() => {
    return () => {
      cleanupAudio();
    };
  }, []);

  // Adaptive Progress Bar Logic (Updated for Two-Pass)
  useEffect(() => {
    let progressInterval: number;

    if (isAnalyzing) {
        setAnalysisProgress(0);
        setStatusMessage("Initializing...");

        // Estimate based on file length
        // Long files need significantly more time for the Two-Pass (Transcribe -> Analyze)
        const isLongFile = timer > 120;
        const estimatedWaitTime = isLongFile ? 120 : 40; 
        const intervalTime = (estimatedWaitTime * 1000) / 100;

        progressInterval = window.setInterval(() => {
            setAnalysisProgress(prev => {
                const increment = prev < 50 ? 1 : prev < 80 ? 0.5 : 0.2;
                const next = prev + increment;

                // Detailed Status Updates for User
                if (next < 20) setStatusMessage("Uploading audio...");
                else if (next < 50) setStatusMessage("Step 1: Transcribing speech...");
                else if (next < 80) setStatusMessage("Step 2: Analyzing grammar & vocabulary...");
                else setStatusMessage("Finalizing report...");

                return next >= 95 ? 95 : next;
            });
        }, intervalTime);
    } else {
        setAnalysisProgress(0);
    }

    return () => clearInterval(progressInterval);
  }, [isAnalyzing, timer]);

  const cleanupAudio = () => {
    if (timerIntervalRef.current) {
        clearInterval(timerIntervalRef.current);
        timerIntervalRef.current = null;
    }
    if (animationFrameRef.current) {
        cancelAnimationFrame(animationFrameRef.current);
        animationFrameRef.current = null;
    }
    if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') {
      mediaRecorderRef.current.stop();
    }

    if (audioContextRef.current) {
        if (audioContextRef.current.state !== 'closed') {
            audioContextRef.current.close().catch(e => console.warn("Error closing AudioContext:", e));
        }
        audioContextRef.current = null;
    }
  };

  // Helper to find the best supported MIME type for the user's browser
  const getSupportedMimeType = () => {
      // Prioritize modern, high-efficiency containers.
      // Safari requires mp4/aac often. Chrome/Android likes webm.
      const types = [
          'audio/webm;codecs=opus', 
          'audio/webm', 
          'audio/mp4', 
          'audio/aac',
          'audio/ogg'
      ];
      for (const type of types) {
          if (MediaRecorder.isTypeSupported(type)) return type;
      }
      return ''; 
  };

  const startRecording = async () => {
    setError(null);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      // Determine the correct MIME type for this device
      const selectedMimeType = getSupportedMimeType();
      if (!selectedMimeType) {
          setError("Your browser does not support audio recording.");
          return;
      }
      activeMimeTypeRef.current = selectedMimeType;
      console.log("Using MIME Type:", selectedMimeType);

      // Audio Context for Visualizer
      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
      const analyser = audioCtx.createAnalyser();
      analyser.fftSize = 128; 
      const source = audioCtx.createMediaStreamSource(stream);
      source.connect(analyser);

      audioContextRef.current = audioCtx;
      analyserRef.current = analyser;
      sourceRef.current = source;

      const bufferLength = analyser.frequencyBinCount;
      const dataArray = new Uint8Array(bufferLength);

      const updateVisualizer = () => {
          if (!analyserRef.current) return;
          analyserRef.current.getByteFrequencyData(dataArray);
          const barCount = 30;
          const step = Math.floor((bufferLength * 0.7) / barCount); 
          const newVisuals = [];
          for(let i = 0; i < barCount; i++) {
              const val = dataArray[i * step];
              const height = Math.max(5, (val / 255) * 100); 
              newVisuals.push(height);
          }
          setVisualizerData(newVisuals);
          animationFrameRef.current = requestAnimationFrame(updateVisualizer);
      };

      updateVisualizer();

      // IMPORTANT: Do NOT set audioBitsPerSecond. Let the device choose its native rate.
      // Setting this causes failures on some iOS versions or specific hardware.
      const options = { mimeType: selectedMimeType };

      const mediaRecorder = new MediaRecorder(stream, options);
      mediaRecorderRef.current = mediaRecorder;
      chunksRef.current = [];

      mediaRecorder.ondataavailable = (e) => {
        if (e.data.size > 0) chunksRef.current.push(e.data);
      };

      mediaRecorder.onstop = async () => {
        // Create blob using the EXACT mime type we recorded with
        const blob = new Blob(chunksRef.current, { type: selectedMimeType });

        if (blob.size === 0) {
            setError("Recording failed (Empty audio). Please try again.");
            return;
        }

        // CRITICAL: Gemini requires simple MIME types.
        // It often rejects 'audio/webm;codecs=opus' but accepts 'audio/webm' or 'audio/mp4'.
        // We strip the codec information before sending to the API.
        const safeMimeType = selectedMimeType.split(';')[0].trim();

        const reader = new FileReader();
        reader.readAsDataURL(blob);
        reader.onloadend = () => {
          const base64String = (reader.result as string).split(',')[1];
          // Pass the cleaned MIME type to the service
          onAnalyze(base64String, timerRef.current, safeMimeType);
        };
      };

      // Start recording with 1000ms timeslices to ensure ondataavailable fires periodically
      mediaRecorder.start(1000); 
      setRecording(true);
      setTimer(0);
      timerRef.current = 0;

      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
      timerIntervalRef.current = window.setInterval(() => {
        setTimer(prev => {
          const next = prev + 1;
          timerRef.current = next;
          if (next >= MAX_RECORDING_TIME) { 
            setTimeout(() => stopRecording(), 0);
            return MAX_RECORDING_TIME;
          }
          return next;
        });
      }, 1000);

    } catch (err) {
      console.error(err);
      setError("Could not access microphone. Please check system permissions.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') {
      mediaRecorderRef.current.stop();
      setRecording(false);

      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);

      if (audioContextRef.current) {
        if (audioContextRef.current.state !== 'closed') {
            audioContextRef.current.close().catch(e => console.warn("Error closing AudioContext:", e));
        }
        audioContextRef.current = null;
      }

      setVisualizerData(new Array(30).fill(5)); 

      if (timerIntervalRef.current) {
        clearInterval(timerIntervalRef.current);
        timerIntervalRef.current = null;
      }

      if (mediaRecorderRef.current.stream) {
          mediaRecorderRef.current.stream.getTracks().forEach(track => track.stop());
      }
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const isWarningTime = timer >= WARNING_TIME;
  const isLongRecording = timer > 120; // 2 mins+
  const remainingTime = MAX_RECORDING_TIME - timer;

  return (
    <div className="flex flex-col items-center justify-center py-6 md:py-12 animate-fade-in max-w-2xl mx-auto w-full px-4">
      {!isAnalyzing && (
          <button onClick={onBack} className="self-start text-gray-500 hover:text-white mb-6 flex items-center gap-2">
            ← {text.backToDash}
          </button>
      )}

      <div className="relative w-full max-w-lg mb-8 flex flex-col items-center justify-center">

        <div className={`z-10 bg-gray-900 w-56 h-56 md:w-64 md:h-64 rounded-full flex flex-col items-center justify-center border-4 shadow-[0_0_50px_rgba(0,0,0,0.5)] relative overflow-hidden transition-colors duration-500 ${isWarningTime ? 'border-red-600 shadow-[0_0_50px_rgba(220,38,38,0.3)]' : 'border-gray-800 shadow-[0_0_50px_rgba(0,68,255,0.15)]'}`}>
            <div className="relative z-20 flex flex-col items-center p-4 rounded-full">
                <div className={`text-4xl md:text-5xl font-mono font-bold mb-2 drop-shadow-md transition-colors ${isWarningTime ? 'text-red-500 animate-pulse' : 'text-white'}`}>
                    {formatTime(timer)}
                </div>
                <p className="text-gray-500 text-xs md:text-sm uppercase tracking-widest drop-shadow-sm font-bold">
                    {recording ? text.recording : text.ready}
                </p>
            </div>
        </div>

        {isWarningTime && recording && (
            <div className="mt-6 bg-red-900/20 border border-red-500/50 px-4 py-2 rounded-lg animate-pulse flex items-center gap-2 text-red-400">
                <span className="font-mono font-bold">Recording ends in {remainingTime}s</span>
            </div>
        )}

        <div className="mt-8 h-16 flex items-center justify-center gap-1.5 w-full max-w-sm px-4">
            {visualizerData.map((height, i) => (
                <div 
                    key={i}
                    className={`w-1.5 md:w-2 rounded-full transition-all duration-75 ease-linear ${isWarningTime ? 'bg-red-500' : 'bg-blue-500'}`}
                    style={{ 
                        height: recording ? `${height}%` : '4px',
                        minHeight: '4px',
                        opacity: recording ? 0.8 : 0.2
                    }}
                ></div>
            ))}
        </div>
      </div>

      {error && (
        <div className="bg-red-900/30 text-red-400 p-3 rounded-lg mb-6 text-sm border border-red-900">
            {error}
        </div>
      )}

      {isAnalyzing ? (
        <div className="w-full max-w-md space-y-4">
            <div className="flex items-center justify-between text-blue-400 mb-2">
                <div className="flex items-center gap-2">
                    <svg className="animate-spin h-5 w-5" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                    </svg>
                    <span className="font-medium text-sm md:text-base">{text.analyzing}</span>
                </div>
                <span className="text-xs font-mono">{Math.round(analysisProgress)}%</span>
            </div>

            <div className="w-full bg-gray-800 rounded-full h-3 overflow-hidden border border-gray-700">
                <div 
                    className="bg-gradient-to-r from-blue-600 to-purple-500 h-full transition-all duration-300 ease-out shadow-[0_0_10px_rgba(59,130,246,0.5)]"
                    style={{ width: `${analysisProgress}%` }}
                ></div>
            </div>

            <div className="text-center mt-3 space-y-1">
                <p className="text-blue-300 text-sm font-semibold animate-pulse">{statusMessage}</p>
                {isLongRecording && (
                    <p className="text-gray-500 text-xs">Deep analysis for long audio enabled...</p>
                )}
            </div>
        </div>
      ) : (
        <div className="flex flex-col md:flex-row gap-4 w-full md:w-auto">
            {!recording ? (
                <button 
                    onClick={startRecording}
                    className="flex items-center justify-center gap-3 px-8 py-4 rounded-full bg-blue-600 hover:bg-blue-500 text-white font-bold text-lg shadow-lg shadow-blue-900/50 transition-all hover:scale-105 w-full md:w-auto"
                >
                    <div className="w-4 h-4 bg-white rounded-full animate-pulse"></div>
                    {text.startRecording}
                </button>
            ) : (
                <button 
                    onClick={stopRecording}
                    className="flex items-center justify-center gap-3 px-8 py-4 rounded-full bg-gray-800 hover:bg-gray-700 text-white font-bold text-lg border-2 border-gray-600 transition-all hover:scale-105 w-full md:w-auto"
                >
                    <div className="w-4 h-4 bg-red-500 rounded-sm"></div>
                    {text.stopRecording}
                </button>
            )}
        </div>
      )}

      <div className="mt-12 text-center max-w-md">
        <p className="text-gray-400 text-xs md:text-sm">{text.tip}</p>
      </div>
    </div>
  );
};

export default AudioRecorder;

import React, { useState, useEffect } from 'react';
import { UserProfile, AIAnalysis, AppView, Language } from './types';
import Header from './components/Header';
import Onboarding from './components/Onboarding';
import AudioRecorder from './components/AudioRecorder';
import FeedbackDisplay from './components/FeedbackDisplay';
import Dashboard from './components/Dashboard';
import Profile from './components/Profile';
import { analyzeAudio } from './services/geminiService';
import { supabase } from './services/supabaseClient';
import { translations } from './utils/translations';
import { checkAndEnforceVersion } from './utils/versionManager';

// We now read the version from the manifest via the manager, 
// but we keep this for the UI display.
// IMPORTANT: Update 'version.json' when you update this!
const UI_VERSION = '1.0.23'; 

const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [userId, setUserId] = useState<string | null>(null); // Supabase Auth ID
  const [view, setView] = useState<AppView>(AppView.ONBOARDING);
  const [history, setHistory] = useState<AIAnalysis[]>([]);
  const [currentAnalysis, setCurrentAnalysis] = useState<AIAnalysis | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [showResetButton, setShowResetButton] = useState(false); // Fail-safe button

  // Recovery Mode State (For Password Reset)
  const [isRecoveryMode, setIsRecoveryMode] = useState(false);

  // Language State - Default to Traditional Chinese ('zh')
  const [language, setLanguage] = useState<Language>('zh');
  const text = translations[language];

  // Initialize Session
  useEffect(() => {

    // --- STEP 1: VERSION CHECK ---
    // This runs immediately. If update is found, it reloads the page before app initializes.
    checkAndEnforceVersion();

    // Timer to show the "Reset" button if loading takes too long (e.g. > 4 seconds)
    const resetTimer = setTimeout(() => {
        if (isLoading) setShowResetButton(true);
    }, 4000);

    const initApp = async () => {
        // SAFETY TIMEOUT: Force loading to stop after 7 seconds max
        const timeoutPromise = new Promise((_, reject) => 
            setTimeout(() => reject(new Error("Initialization timed out")), 7000)
        );

        const sessionPromise = async () => {
            const { data, error } = await supabase.auth.getSession();
            if (error) throw error;

            if (data?.session) {
                await loadUserData(data.session.user.id, data.session.user.email || '');
            } else {
                setView(AppView.ONBOARDING);
            }
        };

        try {
            await Promise.race([sessionPromise(), timeoutPromise]);
        } catch (error) {
            console.warn("App Initialization fallback:", error);
            // If anything fails or times out, default to Onboarding so user isn't stuck
            if (!userId) setView(AppView.ONBOARDING);
        } finally {
            setIsLoading(false);
            clearTimeout(resetTimer);
        }
    };

    initApp();

    // 2. Listen for Auth Changes (Password Recovery / Login / Logout)
    const { data: authListener } = supabase.auth.onAuthStateChange(async (event, session) => {
        if (event === 'PASSWORD_RECOVERY') {
            setIsRecoveryMode(true);
            setView(AppView.PROFILE); // Direct user to profile to change password
            setIsLoading(false);
        } else if (event === 'SIGNED_IN' && session) {
             // Only reload if we aren't already loaded (prevents double firing)
             if (!userId) {
                await loadUserData(session.user.id, session.user.email || '');
             }
        } else if (event === 'SIGNED_OUT') {
            setUser(null);
            setUserId(null);
            setHistory([]);
            setCurrentAnalysis(null);
            setView(AppView.ONBOARDING);
            setIsRecoveryMode(false);
            setIsLoading(false);
        }
    });

    return () => {
        authListener.subscription.unsubscribe();
        clearTimeout(resetTimer);
    };
  }, []);

  // Helper to calculate XP/Level from history list
  const calculateGamification = (historyList: AIAnalysis[]) => {
      let totalXP = 0;
      historyList.forEach(item => {
          const wordCount = item.transcript ? item.transcript.split(' ').length : 0;
          // Formula: Score + (Words * 0.5)
          // Rewards length/effort even if score is low
          totalXP += Math.round(item.score + (wordCount * 0.5));
      });

      // PROGRESSIVE LEVELING FORMULA
      // Level 1 -> 2: 300 XP
      // Increase by 500 XP per level until Cap of 3000 XP

      let level = 1;
      let costForNext = 300;
      let remainingXP = totalXP;

      while (remainingXP >= costForNext) {
          remainingXP -= costForNext;
          level++;

          // Progressive Increase
          costForNext += 500;

          // Cap at 3000
          if (costForNext > 3000) costForNext = 3000;
      }

      return { totalXP, level };
  };

  const loadUserData = async (uid: string, email: string) => {
    try {
      setUserId(uid);

      // 1. Fetch Profile (Base Data)
      let profileBase = { name: 'Student', streak: 0, lastRecordingDate: null as string | null };

      const { data: profileData, error: profileError } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', uid)
        .single();

      if (!profileError && profileData) {
        profileBase = {
            name: profileData.name,
            streak: profileData.streak || 0,
            lastRecordingDate: profileData.last_recording_date
        };
      } else {
          // Fallback if profile missing
          const { data: { user: authUser } } = await supabase.auth.getUser();
          profileBase.name = authUser?.user_metadata?.name || 'Student';
      }

      // 2. Fetch History
      const { data: historyData, error: historyError } = await supabase
        .from('history')
        .select('*')
        .eq('user_id', uid)
        .order('created_at', { ascending: true });

      let loadedHistory: AIAnalysis[] = [];
      if (!historyError && historyData) {
        loadedHistory = historyData.map((h: any) => ({
          transcript: h.transcript,
          score: h.score,
          grammarScore: h.grammar_score,
          pronunciationScore: h.pronunciation_score,
          fluencyScore: h.fluency_score,
          vocabularyScore: h.vocabulary_score,
          feedback: h.feedback || [], 
          tips: h.tips || [], 
          encouragement: h.encouragement,
          timestamp: h.created_at
        }));
        setHistory(loadedHistory);
      }

      // 3. Calculate Dynamic XP/Level
      const { totalXP, level } = calculateGamification(loadedHistory);

      setUser({
        name: profileBase.name,
        email: email,
        streak: profileBase.streak,
        lastRecordingDate: profileBase.lastRecordingDate,
        xp: totalXP,
        level: level
      });

      // Only go to dashboard if NOT in recovery mode
      if (!isRecoveryMode) {
          setView(AppView.DASHBOARD);
      }
    } catch (e) {
      console.error("Error loading user data", e);
      // If error occurs but session exists, we should probably still show dashboard or handle gracefully
    } finally {
      setIsLoading(false);
    }
  };

  // Handle Authentication (Login/Signup)
  const handleAuth = async (email: string, password: string, name: string, mode: 'LOGIN' | 'SIGNUP') => {
    setIsLoading(true);
    try {
      if (mode === 'SIGNUP') {
        const { data, error } = await supabase.auth.signUp({ 
            email, 
            password,
            options: {
                data: { name: name } // Store name in metadata as backup
            }
        });

        if (error) throw error;

        // CRITICAL: Check if session exists. 
        if (data.user && !data.session) {
            alert("Registration successful! Please check your email to verify your account before logging in.");
            setIsLoading(false);
            return; 
        }

        if (data.user && data.session) {
          // Create Profile Row immediately if we have a session
          const { error: profileError } = await supabase.from('profiles').insert({
            id: data.user.id,
            email: email,
            name: name,
            streak: 0,
            last_recording_date: null
          });

          if (profileError) {
              console.error("Profile creation warning:", profileError);
          }

          await loadUserData(data.user.id, email);
        }
      } else {
        // Login
        const { data, error } = await supabase.auth.signInWithPassword({ email, password });
        if (error) throw error;
        if (data.user) {
          await loadUserData(data.user.id, email);
        }
      }
    } catch (error: any) {
      // Suppress console.error for auth failures to prevent alarm
      setIsLoading(false);
      // Re-throw so component can handle UI message
      throw error;
    }
  };

  const handleResetPassword = async (email: string) => {
      // DYNAMIC URL FIX:
      // Uses window.location.origin to work on both Dev and Production (Cloud Run)
      const redirectUrl = window.location.origin;

      const { error } = await supabase.auth.resetPasswordForEmail(email, {
          redirectTo: redirectUrl,
      });
      if (error) throw error;
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setUserId(null);
    setUser(null);
    setHistory([]);
    setCurrentAnalysis(null);
    setView(AppView.ONBOARDING);
  };

  const handleUpdateProfile = async (newName: string, currentPassword?: string, newPassword?: string) => {
    if (!user || !userId) return;

    try {
      // 1. Update Profile Table
      const { error: updateError } = await supabase
        .from('profiles')
        .update({ name: newName })
        .eq('id', userId);

      if (updateError) throw updateError;

      // 2. Update Password (if provided)
      if (newPassword) {
        // If NOT in recovery mode, we MUST verify the old password first for security.
        if (!isRecoveryMode && currentPassword) {
            const { error: verifyError } = await supabase.auth.signInWithPassword({
                email: user.email,
                password: currentPassword
            });

            if (verifyError) {
                throw new Error("Incorrect current password. Cannot update password.");
            }
        }

        // Update to new password
        const { error: pwError } = await supabase.auth.updateUser({ password: newPassword });
        if (pwError) throw pwError;

        // If successful, exit recovery mode
        if (isRecoveryMode) {
            setIsRecoveryMode(false);
            alert("Password updated successfully! Redirecting to Dashboard.");
            setView(AppView.DASHBOARD);
            return; // Exit early to avoid double alert
        }
      }

      // Update Local State (preserve XP/Level)
      setUser({ ...user, name: newName });

    } catch (error: any) {
      console.error("Update failed", error);
      throw error; 
    }
  };

  const handleStartRecording = () => {
    setView(AppView.RECORDING);
  };

  const handleAnalyze = async (audioBase64: string, duration: number, mimeType: string) => {
    if (!user || !userId) return;

    setIsAnalyzing(true);
    try {
      // Pass language to Gemini
      const analysis = await analyzeAudio(audioBase64, duration, mimeType, language);

      // Update Streak logic
      const today = new Date().toDateString();
      const lastDate = user.lastRecordingDate ? new Date(user.lastRecordingDate).toDateString() : null;
      const isoTimestamp = new Date().toISOString();

      let newStreak = user.streak;
      if (lastDate !== today) {
          newStreak = user.streak + 1;
      }

      // 1. Save to History DB
      const { error: historyError } = await supabase.from('history').insert({
        user_id: userId,
        transcript: analysis.transcript,
        score: analysis.score,
        grammar_score: analysis.grammarScore,
        pronunciation_score: analysis.pronunciationScore,
        fluency_score: analysis.fluencyScore,
        vocabulary_score: analysis.vocabularyScore,
        feedback: analysis.feedback || [], 
        tips: analysis.tips || [], 
        encouragement: analysis.encouragement,
        created_at: isoTimestamp
      });

      if (historyError) {
          // If error is related to response size, log it but don't crash app if possible
          console.error("Failed to save history:", historyError.message);
      }

      // 2. Update Profile DB (Streak only)
      // We do NOT save XP to DB to avoid schema errors. XP is calculated on load.
      const { error: profileError } = await supabase
        .from('profiles')
        .upsert({ 
          id: userId,
          name: user.name,
          email: user.email,
          streak: newStreak, 
          last_recording_date: isoTimestamp 
        });

      if (profileError) console.error("Failed to update streak", profileError);

      // 3. Update Local State (Recalculate XP)
      analysis.timestamp = isoTimestamp;
      const newHistory = [...history, analysis];
      const { totalXP, level } = calculateGamification(newHistory);

      setUser({
          ...user,
          streak: newStreak,
          lastRecordingDate: isoTimestamp,
          xp: totalXP,
          level: level
      });

      setCurrentAnalysis(analysis);
      setHistory(newHistory);

      setView(AppView.ANALYSIS);
    } catch (error: any) {
      console.error("Analysis Error:", error);
      // Show cleaner error message
      const msg = error.message.includes("Timeout") ? "Analysis timed out. Please try a shorter recording." : error.message;
      alert(`Error: ${msg}`);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleCloseFeedback = () => {
    setCurrentAnalysis(null);
    setView(AppView.DASHBOARD);
  };

  const handleViewHistory = (analysis: AIAnalysis) => {
    setCurrentAnalysis(analysis);
    setView(AppView.ANALYSIS);
  };

  // Manual Hard Reset for "Stuck" scenarios
  const handleManualReset = () => {
      // Clear all local storage to remove potentially corrupt tokens
      localStorage.clear();
      // Force reload the page
      window.location.reload();
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-black flex flex-col items-center justify-center gap-6 p-4 text-center">
        <div className="text-blue-500 animate-pulse text-xl font-serif">Loading Global Voice Club...</div>

        {showResetButton && (
            <div className="animate-fade-in flex flex-col items-center">
                <p className="text-gray-500 text-sm mb-3">Taking longer than usual?</p>
                <button 
                    onClick={handleManualReset}
                    className="px-4 py-2 bg-gray-800 border border-gray-600 rounded-lg text-white hover:bg-gray-700 hover:border-white transition-all flex items-center gap-2 text-sm"
                >
                    <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-4 h-4">
                        <path strokeLinecap="round" strokeLinejoin="round" d="M16.023 9.348h4.992v-.001M2.985 19.644v-4.992m0 0h4.992m-4.993 0 3.181 3.183a8.25 8.25 0 0 0 13.803-3.7M4.031 9.865a8.25 8.25 0 0 1 13.803-3.7l3.181 3.182m0-4.991v4.99" />
                    </svg>
                    Refresh & Fix
                </button>
            </div>
        )}
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-black text-white font-sans selection:bg-blue-600 selection:text-white overflow-x-hidden w-full flex flex-col">
      <Header 
        user={user} 
        text={text}
        language={language}
        version={UI_VERSION}
        onToggleLanguage={() => setLanguage(l => l === 'en' ? 'zh' : 'en')}
        onLogout={handleLogout} 
        onProfileClick={() => setView(AppView.PROFILE)}
        onLogoClick={() => setView(AppView.DASHBOARD)}
      />

      {/* 
        LAYOUT FIX: 
        Replaced 'container' and 'max-w-full' with an explicit centered container.
        This fixes the off-center issue on mobile devices.
      */}
      <main className="w-full max-w-[95%] 2xl:max-w-[1800px] mx-auto px-4 md:px-8 pt-6 pb-12 flex-grow">
        {view === AppView.ONBOARDING && (
          <Onboarding 
            onAuth={handleAuth} 
            onResetPassword={handleResetPassword}
            text={text}
          />
        )}

        {view === AppView.DASHBOARD && user && (
          <Dashboard 
            user={user} 
            history={history} 
            onStartRecording={handleStartRecording}
            onViewHistory={handleViewHistory}
            text={text}
          />
        )}

        {view === AppView.PROFILE && user && (
            <Profile 
                user={user}
                history={history}
                onUpdateProfile={handleUpdateProfile}
                onBack={() => setView(AppView.DASHBOARD)}
                text={text}
                isRecoveryMode={isRecoveryMode}
            />
        )}

        {view === AppView.RECORDING && (
          <AudioRecorder 
            onAnalyze={handleAnalyze} 
            isAnalyzing={isAnalyzing}
            onBack={() => setView(AppView.DASHBOARD)}
            text={text}
          />
        )}

        {view === AppView.ANALYSIS && currentAnalysis && user && (
          <FeedbackDisplay 
            analysis={currentAnalysis} 
            userName={user.name}
            userEmail={user.email}
            onClose={handleCloseFeedback}
            text={text}
          />
        )}
      </main>
    </div>
  );
};

