import { GoogleGenAI, Type, Schema, HarmCategory, HarmBlockThreshold } from "@google/genai";
import { AIAnalysis } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// --- SCHEMAS ---

// 1. Full Analysis Schema (Complex)
const analysisSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    score: { type: Type.NUMBER, description: "Overall score 0-100." },
    grammarScore: { type: Type.NUMBER, description: "Grammar score 0-100." },
    pronunciationScore: { type: Type.NUMBER, description: "Pronunciation score 0-100." },
    fluencyScore: { type: Type.NUMBER, description: "Fluency score 0-100." },
    vocabularyScore: { type: Type.NUMBER, description: "Vocabulary score 0-100." },
    feedback: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          original: { type: Type.STRING },
          correction: { type: Type.STRING },
          explanation: { type: Type.STRING },
        },
        required: ["original", "correction", "explanation"]
      }
    },
    tips: { type: Type.ARRAY, items: { type: Type.STRING } },
    encouragement: { type: Type.STRING },
  },
  required: ["score", "grammarScore", "pronunciationScore", "fluencyScore", "vocabularyScore", "feedback", "tips", "encouragement"],
};

// 2. Transcript-Only Schema (Simple & Fast)
const transcriptSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    transcript: { type: Type.STRING, description: "Verbatim transcription of the audio." },
  },
  required: ["transcript"]
};

// --- HELPERS ---

const extractAndRepairJSON = (text: string): string => {
  try {
    const jsonMatch = text.match(/\{[\s\S]*\}/);
    let cleanJson = jsonMatch ? jsonMatch[0] : text.replace(/```json/g, '').replace(/```/g, '').trim();

    const openBraces = (cleanJson.match(/\{/g) || []).length;
    const closeBraces = (cleanJson.match(/\}/g) || []).length;
    const openBrackets = (cleanJson.match(/\[/g) || []).length;
    const closeBrackets = (cleanJson.match(/\]/g) || []).length;

    if (openBrackets > closeBrackets) cleanJson += ']'.repeat(openBrackets - closeBrackets);
    if (openBraces > closeBraces) cleanJson += '}'.repeat(openBraces - closeBraces);

    return cleanJson;
  } catch (e) {
    return text;
  }
};

const generateRequest = async (
    modelName: string,
    contents: any,
    schema: Schema,
    timeoutMs: number,
    systemInstruction?: string,
    signal?: AbortSignal
): Promise<any> => {

    const controller = new AbortController();
    const effectiveSignal = signal || controller.signal;

    try {
        const responsePromise = ai.models.generateContent({
            model: modelName,
            contents: contents,
            config: {
                responseMimeType: "application/json",
                responseSchema: schema,
                systemInstruction: systemInstruction,
                maxOutputTokens: 20000, 
                temperature: 0.4, 
                safetySettings: [
                     { category: HarmCategory.HARM_CATEGORY_HATE_SPEECH, threshold: HarmBlockThreshold.BLOCK_NONE },
                     { category: HarmCategory.HARM_CATEGORY_SEXUALLY_EXPLICIT, threshold: HarmBlockThreshold.BLOCK_NONE },
                     { category: HarmCategory.HARM_CATEGORY_DANGEROUS_CONTENT, threshold: HarmBlockThreshold.BLOCK_NONE },
                     { category: HarmCategory.HARM_CATEGORY_HARASSMENT, threshold: HarmBlockThreshold.BLOCK_NONE }
                ]
            }
        });

        const timeoutPromise = new Promise((_, reject) => 
            setTimeout(() => {
                controller.abort(); 
                reject(new Error(`Timeout after ${timeoutMs}ms`));
            }, timeoutMs)
        );

        const result: any = await Promise.race([responsePromise, timeoutPromise]);

        if (!result.text) throw new Error("Empty response from AI");

        const cleanText = extractAndRepairJSON(result.text);
        return JSON.parse(cleanText);

    } catch (error) {
        console.warn("AI Generation Warning:", error); 
        throw error;
    }
};

// --- CORE SERVICES ---

const analyzeDirectly = async (base64Audio: string, mimeType: string, langInstruction: string, contextInstruction: string, signal?: AbortSignal) => {
    // Increased timeout for direct analysis because we are now sending potentially longer files (up to 5 mins)
    // direct to Gemini 2.5 Flash. Flash is fast, but 5 mins is still a lot of data.
    return await generateRequest(
        'gemini-2.5-flash',
        {
            parts: [
                { inlineData: { data: base64Audio, mimeType: mimeType } },
                { text: `Transcribe and Analyze. Return raw JSON. Limit feedback to TOP 10 errors. IGNORE punctuation mistakes.` }
            ]
        },
        { ...analysisSchema, properties: { ...analysisSchema.properties, transcript: { type: Type.STRING } }, required: [...(analysisSchema.required || []), "transcript"] },
        150000, // 2.5 Minutes max for direct
        `${langInstruction} ${contextInstruction} JSON ONLY. No Markdown. Concise explanations.`,
        signal
    );
};

const transcribeOnly = async (base64Audio: string, mimeType: string, signal?: AbortSignal) => {
    return await generateRequest(
        'gemini-2.5-flash',
        {
            parts: [
                { inlineData: { data: base64Audio, mimeType: mimeType } },
                { text: "Transcribe verbatim. No markdown." }
            ]
        },
        transcriptSchema,
        180000, // 3 mins max
        undefined,
        signal
    );
};

const analyzeText = async (transcript: string, langInstruction: string, contextInstruction: string, signal?: AbortSignal) => {
    return await generateRequest(
        'gemini-2.5-flash',
        {
            parts: [{ text: `Analyze transcript: "${transcript}".` }]
        },
        analysisSchema,
        120000, // 2 mins max
        `${langInstruction} ${contextInstruction} Find top 10 critical mistakes. IGNORE punctuation errors. Strict JSON output. Concise explanations.`,
        signal
    );
};

const generateEmergencyFallback = (transcript: string | null): AIAnalysis => {
    const wordCount = transcript ? transcript.split(' ').length : 0;
    const baseScore = Math.min(85, 60 + (wordCount / 5)); 

    return {
        transcript: transcript || "Audio processed, but detailed analysis timed out. Here is a provisional score.",
        score: Math.round(baseScore),
        grammarScore: Math.round(baseScore - 5),
        pronunciationScore: Math.round(baseScore + 5),
        fluencyScore: Math.round(baseScore),
        vocabularyScore: Math.round(baseScore - 2),
        feedback: [],
        tips: ["Try to speak more clearly.", "Check your microphone connection.", "Practice short sentences first."],
        encouragement: "Great effort! Our AI had trouble analyzing this long session in detail, but keep practicing!",
        timestamp: new Date().toISOString()
    };
};

// --- MAIN EXPORT ---

export const analyzeAudio = async (base64Audio: string, duration: number, mimeType: string, language: 'en' | 'zh'): Promise<AIAnalysis> => {

    // 12MB Payload Limit
    if (base64Audio.length > 12 * 1024 * 1024) {
        throw new Error("File too large. Please record a shorter clip.");
    }

    let langContext = "You are a strict English teacher. Provide all feedback, tips, and explanations in ENGLISH ONLY. Do NOT correct punctuation or capitalization."; 
    if (language === 'zh') {
        langContext = "You are a friendly Taiwanese ESL teacher. Provide the 'explanation', 'tips', and 'encouragement' in TRADITIONAL CHINESE (Taiwan). However, the 'correction' field must remain in English. Do NOT correct punctuation or capitalization.";
    }

    const conversationContext = "Ignore silence. This is a one-sided recording of a conversation.";

    // SMART ROUTING LOGIC:
    // Gemini 2.5 Flash is very fast. It can handle long context (5 mins).
    // The main bottleneck is UPLOAD speed and server processing time.
    // If the file is compressed well (small size), Direct Analysis is faster than Two-Pass (which requires two round trips).
    // We only force Two-Pass if the payload is HUGE (> 4MB).
    const isLargePayload = base64Audio.length > 4 * 1024 * 1024; // > 4MB (approx)

    // GLOBAL TIMEOUT RACE
    // Cap at 180s (3 minutes). Anything longer than that is bad UX.
    const GLOBAL_TIMEOUT = 180000; 

    const controller = new AbortController();

    return new Promise(async (resolve) => {
        const timeoutId = setTimeout(() => {
            console.warn("Global Analysis Timeout. Returning Emergency Fallback.");
            controller.abort(); 
            resolve(generateEmergencyFallback("Analysis timed out due to high load."));
        }, GLOBAL_TIMEOUT);

        try {
            if (isLargePayload) {
                console.log(`Large payload (${(base64Audio.length/1024/1024).toFixed(2)}MB). Force Two-Pass.`);
                throw new Error("Force Two-Pass");
            }

            // --- ATTEMPT 1: Fast Path (Direct Analysis) ---
            console.log("Attempting Direct Analysis (Fast Path)...");
            const result = await analyzeDirectly(base64Audio, mimeType, langContext, conversationContext, controller.signal);
            clearTimeout(timeoutId);
            resolve({ ...result, timestamp: new Date().toISOString() });

        } catch (error) {
            console.warn("Direct analysis failed/skipped. Switching to Robust Two-Pass...", error);

            try {
                // --- ATTEMPT 2: Robust Path (Transcribe -> Analyze) ---
                console.log("Step 1: Transcribing...");
                const { transcript } = await transcribeOnly(base64Audio, mimeType, controller.signal);

                if (!transcript || transcript.length < 5) {
                    throw new Error("Audio was empty or unintelligible.");
                }

                console.log("Step 2: Analyzing Text...");
                const analysis = await analyzeText(transcript, langContext, conversationContext, controller.signal);

                clearTimeout(timeoutId);
                resolve({
                    ...analysis,
                    transcript: transcript,
                    timestamp: new Date().toISOString()
                });

            } catch (fatalError: any) {
                console.error("Critical Failure:", fatalError);
                clearTimeout(timeoutId);
                resolve(generateEmergencyFallback(null));
            }
        }
    });
};

import React, { useState } from 'react';
import { UserProfile, AIAnalysis, AppText } from '../types';

interface ProfileProps {
  user: UserProfile;
  history: AIAnalysis[];
  onUpdateProfile: (name: string, currentPassword?: string, newPassword?: string) => Promise<void>;
  onBack: () => void;
  text: AppText;
  isRecoveryMode: boolean;
}

const Profile: React.FC<ProfileProps> = ({ user, history, onUpdateProfile, onBack, text, isRecoveryMode }) => {
  const [name, setName] = useState(user.name);

  // Password State
  const [currentPassword, setCurrentPassword] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');

  const [showPassword, setShowPassword] = useState(false);
  const [message, setMessage] = useState('');
  const [isSaving, setIsSaving] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim()) return;

    // Password Validation
    const isChangingPassword = newPassword.trim().length > 0;

    if (isChangingPassword) {
        if (!currentPassword && !isRecoveryMode) {
            setMessage("Error: Please enter your current password to confirm changes.");
            return;
        }
        if (newPassword !== confirmPassword) {
            setMessage("Error: New passwords do not match.");
            return;
        }
        if (newPassword.length < 6) {
            setMessage("Error: Password must be at least 6 characters.");
            return;
        }
    }

    setIsSaving(true);
    try {
        await onUpdateProfile(name, isChangingPassword ? currentPassword : undefined, isChangingPassword ? newPassword : undefined);
        setMessage('Profile updated successfully!');

        // Clear password fields
        setCurrentPassword('');
        setNewPassword('');
        setConfirmPassword('');

        setTimeout(() => setMessage(''), 3000);
    } catch (e: any) {
        setMessage(`Error: ${e.message || "Failed to update profile"}`);
    } finally {
        setIsSaving(false);
    }
