            <div className={`mb-6 p-3 border rounded-lg text-sm text-center ${message.includes('Error') ? 'bg-red-900/30 border-red-800 text-red-400' : 'bg-green-900/30 border-green-800 text-green-400'}`}>
                {message}
            </div>
