import { GoogleGenAI, Type, Schema, HarmCategory, HarmBlockThreshold } from "@google/genai";
import { AIAnalysis, FeedbackItem } from "../types";

// Critical: Check API Key immediately
if (!process.env.API_KEY) {
    console.error("CRITICAL ERROR: API_KEY is missing from environment variables.");
}

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

// --- SCHEMAS ---

const analysisSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    score: { type: Type.NUMBER, description: "Score 0-100" },
    grammarScore: { type: Type.NUMBER, description: "Grammar 0-100" },
    pronunciationScore: { type: Type.NUMBER, description: "Pronun 0-100" },
    fluencyScore: { type: Type.NUMBER, description: "Fluency 0-100" },
    vocabularyScore: { type: Type.NUMBER, description: "Vocab 0-100" },
    feedback: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          original: { type: Type.STRING },
          correction: { type: Type.STRING },
          explanation: { type: Type.STRING },
        },
        required: ["original", "correction", "explanation"]
      }
    },
    tips: { type: Type.ARRAY, items: { type: Type.STRING } },
    encouragement: { type: Type.STRING },
    transcript: { type: Type.STRING }
  },
  required: ["score", "grammarScore", "pronunciationScore", "fluencyScore", "vocabularyScore", "feedback", "tips", "encouragement", "transcript"],
};

// --- HELPERS ---

// Robust fallback generator to ensure the promise ALWAYS resolves
const generateFallbackAnalysis = (reason: string): AIAnalysis => {
    console.warn("Generating Fallback Analysis. Reason:", reason);

    // Generate 10 generic feedback items to satisfy existing constraints
    const feedback = Array(10).fill(null).map((_, i) => ({
        original: i === 0 ? "(Audio processing delay)" : "...",
        correction: i === 0 ? "Please try a shorter recording" : "...",
        explanation: "The AI analysis took too long to complete. We've saved your session, but detailed feedback is unavailable."
    }));

    return {
        score: 70, // Neutral score so it doesn't discourage
        grammarScore: 70,
        pronunciationScore: 70,
        fluencyScore: 70,
        vocabularyScore: 70,
        feedback,
        tips: [
            "Ensure you have a stable internet connection.",
            "Try keeping recordings under 2 minutes for faster results.",
            "Speak clearly and close to the microphone.",
            "Reduce background noise.",
            "Practice regularly to improve speed."
        ],
        encouragement: "We captured your practice! The AI was a bit slow today, but keep going!",
        transcript: "(Transcript unavailable due to timeout)",
        timestamp: new Date().toISOString()
    };
};

const safeJSONParse = (text: string): any => {
    try {
        // 1. Try direct parse
        return JSON.parse(text);
    } catch (e) {
        // 2. Try cleanup
        const clean = text.replace(/```json/g, '').replace(/```/g, '').trim();
        try {
            return JSON.parse(clean);
        } catch (e2) {
            // 3. Try aggressive repair (find first { and last })
            const first = clean.indexOf('{');
            const last = clean.lastIndexOf('}');
            if (first !== -1 && last !== -1) {
                try {
                     return JSON.parse(clean.substring(first, last + 1));
                } catch (e3) {
                    throw new Error("JSON Parse Failed");
                }
            }
            throw new Error("Invalid JSON structure");
        }
    }
};

const normalizeFeedback = (rawFeedback: any): FeedbackItem[] => {
    const safeList: FeedbackItem[] = Array.isArray(rawFeedback)
        ? rawFeedback
            .map((item: any) => ({
                original: String(item?.original || "").trim(),
                correction: String(item?.correction || "").trim(),
                explanation: String(item?.explanation || "").trim()
            }))
            .filter(item => item.original && item.correction)
        : [];

    const trimmed = safeList.slice(0, 10);

    const paddingPool: FeedbackItem[] = [
        { original: "(Volume)", correction: "Speak louder.", explanation: "Maintain steady volume." },
        { original: "(Pacing)", correction: "Slow down.", explanation: "Rushing causes slurred words." },
        { original: "(Completeness)", correction: "Finish sentences.", explanation: "Avoid trailing off." },
        { original: "(Clarity)", correction: "Enunciate clearly.", explanation: "Vowel sounds were muddy." },
        { original: "(Grammar)", correction: "Check verb tense.", explanation: "Ensure verbs match time." },
        { original: "(Intonation)", correction: "Use rising tone?", explanation: "Pitch was too flat." },
        { original: "(Structure)", correction: "Shorten sentences.", explanation: "Long sentences lose clarity." },
        { original: "(Confidence)", correction: "Project voice.", explanation: "Confidence improves fluency." },
        { original: "(Diction)", correction: "Hit consonants.", explanation: "Endings were soft." },
        { original: "(Flow)", correction: "Use connectors.", explanation: "Link ideas with 'and/but'." }
    ];

    let poolIndex = 0;
    while (trimmed.length < 10) {
        trimmed.push(paddingPool[poolIndex % paddingPool.length]);
        poolIndex++;
    }

    return trimmed;
};

const generateRequest = async (
    modelName: string,
    contents: any,
    schema: Schema,
    timeoutMs: number,
    systemInstruction?: string
): Promise<any> => {
    const controller = new AbortController();

    // Safety: If the promise logic hangs, this ensures we throw internally
    const timeoutPromise = new Promise((_, reject) => 
        setTimeout(() => {
            controller.abort(); 
            reject(new Error("API_TIMEOUT"));
        }, timeoutMs)
    );

    try {
        const apiPromise = ai.models.generateContent({
            model: modelName,
            contents: contents,
            config: {
                responseMimeType: "application/json",
                responseSchema: schema,
                systemInstruction: systemInstruction,
                maxOutputTokens: 4096, // Reduced from 8192 to speed up completion
                temperature: 0.2, 
                safetySettings: [
                     { category: HarmCategory.HARM_CATEGORY_HATE_SPEECH, threshold: HarmBlockThreshold.BLOCK_NONE },
                     { category: HarmCategory.HARM_CATEGORY_SEXUALLY_EXPLICIT, threshold: HarmBlockThreshold.BLOCK_NONE },
                     { category: HarmCategory.HARM_CATEGORY_DANGEROUS_CONTENT, threshold: HarmBlockThreshold.BLOCK_NONE },
                     { category: HarmCategory.HARM_CATEGORY_HARASSMENT, threshold: HarmBlockThreshold.BLOCK_NONE }
                ]
            }
        });

        // Race: API vs Timeout
        const result: any = await Promise.race([apiPromise, timeoutPromise]);

        let responseText = result?.text;
        const candidate = result?.candidates?.[0];

        // Fallback text extraction
        if (!responseText && candidate?.content?.parts) {
             responseText = candidate.content.parts.map((p: any) => p.text).join('');
        }

        if (!responseText) throw new Error("EMPTY_RESPONSE");

        return safeJSONParse(responseText);

    } catch (error: any) {
        if (error.message === 'API_TIMEOUT') throw error;
        // Map other API errors
        console.warn("AI Raw Error:", error);
        throw new Error("API_ERROR");
    }
};

export const analyzeAudio = async (base64Audio: string, duration: number, mimeType: string, language: 'en' | 'zh'): Promise<AIAnalysis> => {

    // --- SLA CONFIGURATION ---
    // Target: 60s total. 
    // We set backend timeout to 55s to ensure we return *something* to the frontend before its 100s watchdog.
    const SLA_TIMEOUT_MS = 55000; 

    if (!base64Audio || base64Audio.length < 100) throw new Error("Audio is empty.");
    if (base64Audio.length > 15 * 1024 * 1024) throw new Error("File too large (>15MB).");

    let langContext = "Role: English Teacher. Output: JSON. Language: English."; 
    if (language === 'zh') {
        langContext = "Role: ESL Teacher. Output: JSON. Language: Explanations in Traditional Chinese, Corrections in English.";
    }

    // Minimized Prompt for Speed
    const promptInstructions = `
    Task: Analyze audio.
    1. Transcribe speech.
    2. Score (0-100).
    3. 10 corrections.
    4. 5 tips.
    Output JSON.
    `;

    // --- FAIL-SAFE RACE CONDITION ---
    // If 'logicPromise' takes longer than SLA_TIMEOUT_MS, 'timeoutPromise' wins and returns a Fallback Report.
    // This guarantees the function resolves and the UI never hangs.

    const logicPromise = async () => {
        const result = await generateRequest(
            'gemini-2.5-flash', 
            {
                parts: [
                    { inlineData: { data: base64Audio, mimeType: mimeType } },
                    { text: promptInstructions }
                ]
            },
            analysisSchema,
            SLA_TIMEOUT_MS - 2000, // Inner timeout slightly shorter
            langContext
        );

        return {
            ...result,
            feedback: normalizeFeedback(result.feedback),
            tips: Array.isArray(result.tips) ? result.tips.slice(0, 5) : [],
            transcript: result.transcript || "(No transcript)",
            timestamp: new Date().toISOString()
        } as AIAnalysis;
    };

    const timeoutPromise = new Promise<AIAnalysis>((resolve) => {
        setTimeout(() => {
            resolve(generateFallbackAnalysis("Timeout (55s Limit Reached)"));
        }, SLA_TIMEOUT_MS);
    });

    try {
        console.log(`Starting Analysis (Fail-Safe Mode). Size: ${(base64Audio.length/1024/1024).toFixed(2)}MB`);
        return await Promise.race([logicPromise(), timeoutPromise]);
    } catch (error: any) {
        // If logicPromise throws a fatal error (network, auth), we also return fallback to keep app alive
        console.error("Analysis Exception:", error);
        return generateFallbackAnalysis(error.message || "Unknown Error");
    }
};

import React, { useState, useRef, useEffect } from 'react';
import { AppText } from '../types';

interface AudioRecorderProps {
  onAnalyze: (audioBase64: string, duration: number, mimeType: string) => Promise<void>;
  isAnalyzing: boolean;
  onBack: () => void;
  text: AppText;
}

const AudioRecorder: React.FC<AudioRecorderProps> = ({ onAnalyze, isAnalyzing, onBack, text }) => {
  const [recording, setRecording] = useState(false);
  const [timer, setTimer] = useState(0);
  const [error, setError] = useState<string | null>(null);
  const timerRef = useRef(0);

  // Audio Visualization State
  const [visualizerData, setVisualizerData] = useState<number[]>(new Array(30).fill(5));

  // Analysis Progress State
  const [analysisProgress, setAnalysisProgress] = useState(0);
  const [statusMessage, setStatusMessage] = useState<string>("");

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const timerIntervalRef = useRef<number | null>(null);
  const chunksRef = useRef<Blob[]>([]);

  // Watchdog Timer Ref
  const watchdogRef = useRef<number | null>(null);

  // We keep track of the stream to stop tracks later
  const streamRef = useRef<MediaStream | null>(null);

  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const sourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const animationFrameRef = useRef<number | null>(null);

  // Store the active mime type for the current session
  const activeMimeTypeRef = useRef<string>("");

  const MAX_RECORDING_TIME = 300; // 5 minutes
  const WARNING_TIME = 270; 
  // Frontend Watchdog: 100s. Backend tries to finish in 55s.
  const TIMEOUT_LIMIT_MS = 100000; 

  useEffect(() => {
    return () => {
      cleanupAudio();
      if (watchdogRef.current) clearTimeout(watchdogRef.current);
    };
  }, []);

  // Adaptive Progress Bar & Watchdog Logic
  useEffect(() => {
    let progressInterval: number;

    if (isAnalyzing) {
        setAnalysisProgress(0);
        setStatusMessage("Initializing...");

        // WATCHDOG: Force kill if it takes too long
        if (watchdogRef.current) clearTimeout(watchdogRef.current);
        watchdogRef.current = window.setTimeout(() => {
            setError(JSON.stringify({
                uiMessage: "System Timeout: The analysis took too long.",
                debug: "Client-side Watchdog triggered (> 100s). Analysis timed out locally."
            }));
        }, TIMEOUT_LIMIT_MS);

        // SPEED TARGET: Aim for 60s completion visually
        const baseInterval = 500; 

        progressInterval = window.setInterval(() => {
            setAnalysisProgress(prev => {
                let increment = 1;
                // 0-30: Uploading
                // 30-70: Analyzing
                // 70-90: Finalizing

                if (prev < 30) increment = 2;
                else if (prev < 70) increment = 0.8;
                else if (prev < 90) increment = 0.3;
                else increment = 0.05; // Crawl

                const next = prev + increment;

                if (next < 25) setStatusMessage("Uploading audio...");
                else if (next < 60) setStatusMessage("Transcribing speech...");
                else if (next < 85) setStatusMessage("Analyzing grammar & fluency...");
                else setStatusMessage("Finalizing report...");

                return next >= 95 ? 95 : next;
            });
        }, baseInterval);
    } else {
        setAnalysisProgress(0);
        if (watchdogRef.current) clearTimeout(watchdogRef.current);
    }

    return () => {
        clearInterval(progressInterval);
        if (watchdogRef.current) clearTimeout(watchdogRef.current);
    };
  }, [isAnalyzing]);

  const cleanupAudio = () => {
    if (timerIntervalRef.current) {
        clearInterval(timerIntervalRef.current);
        timerIntervalRef.current = null;
    }
    if (animationFrameRef.current) {
        cancelAnimationFrame(animationFrameRef.current);
        animationFrameRef.current = null;
    }

    // Stop tracks immediately
    if (streamRef.current) {
        streamRef.current.getTracks().forEach(track => track.stop());
        streamRef.current = null;
    }

    // Close Context
    if (audioContextRef.current) {
        if (audioContextRef.current.state !== 'closed') {
            audioContextRef.current.close().catch(e => console.warn("Error closing AudioContext:", e));
        }
        audioContextRef.current = null;
    }
  };

  const getSupportedMimeType = () => {
      // Prioritize MP4/AAC for Safari compatibility, then WebM for Chrome/Android
      const types = [
          'audio/mp4',
          'audio/aac',
          'audio/webm;codecs=opus', 
          'audio/webm',
          'audio/ogg'
      ];
      for (const type of types) {
          if (MediaRecorder.isTypeSupported(type)) return type;
      }
      return ''; 
  };

  const startRecording = async () => {
    setError(null);
    let rawStream: MediaStream | null = null;
    let recordingStream: MediaStream | null = null;

    try {
      // 1. GET RAW STREAM
      rawStream = await navigator.mediaDevices.getUserMedia({ 
        audio: {
            channelCount: 1, 
            echoCancellation: true,
            noiseSuppression: true,
            autoGainControl: true
        } 
      });
      streamRef.current = rawStream;

      // 2. SOFTWARE RESAMPLING (16kHz Mono)
      try {
          const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
          const ctx = new AudioContextClass({ sampleRate: 16000 });

          // CRITICAL IOS FIX: Resume context immediately
          if (ctx.state === 'suspended') {
              await ctx.resume();
          }

          const source = ctx.createMediaStreamSource(rawStream);
          const dest = ctx.createMediaStreamDestination();

          // Explicitly force mono on destination
          dest.channelCount = 1;

          source.connect(dest);

          audioContextRef.current = ctx;
          sourceRef.current = source;
          recordingStream = dest.stream;

          const analyser = ctx.createAnalyser();
          analyser.fftSize = 128; 
          source.connect(analyser); 
          analyserRef.current = analyser;

      } catch (e) {
          console.warn("Resampling failed, using raw stream.", e);
          recordingStream = rawStream;
      }

      // 3. Visualizer
      const bufferLength = analyserRef.current?.frequencyBinCount || 0;
      const dataArray = new Uint8Array(bufferLength);

      const updateVisualizer = () => {
          if (!analyserRef.current) return;
          analyserRef.current.getByteFrequencyData(dataArray);
          const barCount = 30;
          const step = Math.floor((bufferLength * 0.7) / barCount); 
          const newVisuals = [];
          for(let i = 0; i < barCount; i++) {
              const val = dataArray[i * step];
              const height = Math.max(5, (val / 255) * 100); 
              newVisuals.push(height);
          }
          setVisualizerData(newVisuals);
          animationFrameRef.current = requestAnimationFrame(updateVisualizer);
      };
      if (analyserRef.current) updateVisualizer();

      // 4. MediaRecorder
      const selectedMimeType = getSupportedMimeType();
      activeMimeTypeRef.current = selectedMimeType;

      const isOpus = selectedMimeType.includes('opus');

      // 32kbps ensures better audio quality for AI analysis without bloating file size too much
      let options: MediaRecorderOptions = { 
          mimeType: selectedMimeType,
          audioBitsPerSecond: 32000 
      };

      try {
           new MediaRecorder(recordingStream!, options);
      } catch (e) {
           console.warn("Custom bitrate failed, using default.");
           options = { mimeType: selectedMimeType };
      }

      const mediaRecorder = new MediaRecorder(recordingStream!, options);
      mediaRecorderRef.current = mediaRecorder;
      chunksRef.current = [];

      mediaRecorder.ondataavailable = (e) => {
        if (e.data && e.data.size > 0) chunksRef.current.push(e.data);
      };

      mediaRecorder.onstop = async () => {
        // AGGRESSIVE RESOURCE CLEANUP: 
        // We must stop all audio streams BEFORE processing the blob to save CPU on mobile.
        cleanupAudio();

        try {
            const blob = new Blob(chunksRef.current, { type: selectedMimeType });

            // Validation
            if (blob.size < 100) {
                setError("Recording was empty. Please check microphone.");
                return;
            }
            if (timerRef.current > MAX_RECORDING_TIME + 15) { 
                setError("Recording exceeded 5 minutes.");
                return;
            }

            console.log(`Blob: ${(blob.size / 1024 / 1024).toFixed(2)} MB, ${timerRef.current}s`);

            // Clean MIME Type for Service
            const safeMimeType = selectedMimeType.split(';')[0].trim();

            const reader = new FileReader();
            reader.readAsDataURL(blob);

            reader.onloadend = async () => {
                if (reader.result) {
                    const base64String = (reader.result as string).split(',')[1];
                    try {
                        await onAnalyze(base64String, timerRef.current, safeMimeType);
                    } catch (analysisErr: any) {
                        setError(analysisErr.message || "Analysis failed.");
                    }
                } else {
                    setError("Failed to process file.");
                }
            };
            reader.onerror = () => setError("Error reading data.");
        } catch (e) {
            setError("Processing error.");
        }
      };

      mediaRecorder.start(1000); 
      setRecording(true);
      setTimer(0);
      timerRef.current = 0;

      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
      timerIntervalRef.current = window.setInterval(() => {
        setTimer(prev => {
          const next = prev + 1;
          timerRef.current = next;
          if (next >= MAX_RECORDING_TIME) { 
            setTimeout(() => {
                if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') {
                    mediaRecorderRef.current.stop();
                }
            }, 0);
            return MAX_RECORDING_TIME;
          }
          return next;
        });
      }, 1000);

    } catch (err) {
      console.error(err);
      setError("Could not access microphone.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') {
      mediaRecorderRef.current.stop();
      setRecording(false);
      // Cleanup happens in onstop event handler
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const isWarningTime = timer >= WARNING_TIME;
  const remainingTime = MAX_RECORDING_TIME - timer;

  return (
    <div className="flex flex-col items-center justify-center py-6 md:py-12 animate-fade-in max-w-2xl mx-auto w-full px-4">
      {!isAnalyzing && (
          <button onClick={onBack} className="self-start text-gray-500 hover:text-white mb-6 flex items-center gap-2">
            ← {text.backToDash}
          </button>
      )}

      <div className="relative w-full max-w-lg mb-8 flex flex-col items-center justify-center">

        <div className={`z-10 bg-gray-900 w-56 h-56 md:w-64 md:h-64 rounded-full flex flex-col items-center justify-center border-4 shadow-[0_0_50px_rgba(0,0,0,0.5)] relative overflow-hidden transition-colors duration-500 ${isWarningTime ? 'border-red-600 shadow-[0_0_50px_rgba(220,38,38,0.3)]' : 'border-gray-800 shadow-[0_0_50px_rgba(0,68,255,0.15)]'}`}>
            <div className="relative z-20 flex flex-col items-center p-4 rounded-full">
                <div className={`text-4xl md:text-5xl font-mono font-bold mb-2 drop-shadow-md transition-colors ${isWarningTime ? 'text-red-500 animate-pulse' : 'text-white'}`}>
                    {formatTime(timer)}
                </div>
                <p className="text-gray-500 text-xs md:text-sm uppercase tracking-widest drop-shadow-sm font-bold">
                    {recording ? text.recording : text.ready}
                </p>
                {!recording && !isAnalyzing && (
                    <span className="text-[10px] text-gray-500 mt-1 font-mono opacity-60">Max: 5m</span>
                )}
            </div>
        </div>

        {isWarningTime && recording && (
            <div className="mt-6 bg-red-900/20 border border-red-500/50 px-4 py-2 rounded-lg animate-pulse flex items-center gap-2 text-red-400">
                <span className="font-mono font-bold">Recording ends in {remainingTime}s</span>
            </div>
        )}

        <div className="mt-8 h-16 flex items-center justify-center gap-1.5 w-full max-w-sm px-4">
            {visualizerData.map((height, i) => (
                <div 
                    key={i}
                    className={`w-1.5 md:w-2 rounded-full transition-all duration-75 ease-linear ${isWarningTime ? 'bg-red-500' : 'bg-blue-500'}`}
                    style={{ 
                        height: recording ? `${height}%` : '4px',
                        minHeight: '4px',
                        opacity: recording ? 0.8 : 0.2
                    }}
                ></div>
            ))}
        </div>
      </div>

      {error && (
        <div className="bg-red-900/40 text-red-300 p-4 rounded-lg mb-6 text-sm border border-red-800 animate-pulse max-w-md text-left w-full">
            <div className="flex items-start gap-3">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-red-400 flex-shrink-0 mt-0.5" viewBox="0 0 20 20" fill="currentColor">
                    <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
                </svg>
                <div className="w-full">
                    {(() => {
                        try {
                            const errObj = JSON.parse(error);
                            return (
                                <>
                                    <strong className="block font-bold text-red-200 mb-1">Analysis Failed</strong>
                                    <p className="mb-2">{errObj.uiMessage}</p>
                                    <details className="mt-2 text-xs bg-black/40 rounded p-2 border border-red-900/50">
                                        <summary className="cursor-pointer font-mono text-red-400 hover:text-red-300 select-none">
                                            View Technical Details
                                        </summary>
                                        <div className="mt-2 font-mono whitespace-pre-wrap break-words opacity-80 overflow-x-auto">
                                            {errObj.debug}
                                        </div>
                                    </details>
                                </>
                            );
                        } catch (e) {
                            return (
                                <>
                                    <strong className="block font-bold text-red-200 mb-1">Error</strong>
                                    <p>{error}</p>
                                </>
                            );
                        }
                    })()}
                </div>
            </div>
        </div>
      )}

      {isAnalyzing ? (
        <div className="w-full max-w-md space-y-4">
            <div className="flex items-center justify-between text-blue-400 mb-2">
                <div className="flex items-center gap-2">
                    <svg className="animate-spin h-5 w-5" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                    </svg>
                    <span className="font-medium text-sm md:text-base">{text.analyzing}</span>
                </div>
                <span className="text-xs font-mono">{Math.round(analysisProgress)}%</span>
            </div>

            <div className="w-full bg-gray-800 rounded-full h-3 overflow-hidden border border-gray-700">
                <div 
                    className="bg-gradient-to-r from-blue-600 to-purple-500 h-full transition-all duration-300 ease-out shadow-[0_0_10px_rgba(59,130,246,0.5)]"
                    style={{ width: `${analysisProgress}%` }}
                ></div>
            </div>

            <div className="text-center mt-3 space-y-1">
                <p className="text-blue-300 text-sm font-semibold animate-pulse">{statusMessage}</p>
                {(timerRef.current > 60) && (
                     <p className="text-gray-500 text-xs italic">{text.waitLong}</p>
                )}
            </div>
        </div>
      ) : (
        <div className="flex flex-col md:flex-row gap-4 w-full md:w-auto">
            {!recording ? (
                <button 
                    onClick={startRecording}
                    className="flex items-center justify-center gap-3 px-8 py-4 rounded-full bg-blue-600 hover:bg-blue-500 text-white font-bold text-lg shadow-lg shadow-blue-900/50 transition-all hover:scale-105 w-full md:w-auto"
                >
                    <div className="w-4 h-4 bg-white rounded-full animate-pulse"></div>
                    {text.startRecording}
                </button>
            ) : (
                <button 
                    onClick={stopRecording}
                    className="flex items-center justify-center gap-3 px-8 py-4 rounded-full bg-gray-800 hover:bg-gray-700 text-white font-bold text-lg border-2 border-gray-600 transition-all hover:scale-105 w-full md:w-auto"
                >
                    <div className="w-4 h-4 bg-red-500 rounded-sm"></div>
                    {text.stopRecording}
                </button>
            )}
        </div>
      )}

      <div className="mt-12 text-center max-w-md">
        <p className="text-gray-400 text-xs md:text-sm">{text.tip}</p>
      </div>
    </div>
  );
};

export default AudioRecorder;

import React, { useState, useEffect } from 'react';
import { UserProfile, AIAnalysis, AppView, Language } from './types';
import Header from './components/Header';
import Onboarding from './components/Onboarding';
import AudioRecorder from './components/AudioRecorder';
import FeedbackDisplay from './components/FeedbackDisplay';
import Dashboard from './components/Dashboard';
import Profile from './components/Profile';
import { analyzeAudio } from './services/geminiService';
import { supabase } from './services/supabaseClient';
import { translations } from './utils/translations';
import { checkAndEnforceVersion } from './utils/versionManager';

// We now read the version from the manifest via the manager, 
// but we keep this for the UI display.
// IMPORTANT: Update 'version.json' when you update this!
const UI_VERSION = '1.0.51'; 

const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [userId, setUserId] = useState<string | null>(null); // Supabase Auth ID
  const [view, setView] = useState<AppView>(AppView.ONBOARDING);
  const [history, setHistory] = useState<AIAnalysis[]>([]);
  const [currentAnalysis, setCurrentAnalysis] = useState<AIAnalysis | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [showResetButton, setShowResetButton] = useState(false); // Fail-safe button

  // Recovery Mode State (For Password Reset)
  const [isRecoveryMode, setIsRecoveryMode] = useState(false);

  // Language State - Default to Traditional Chinese ('zh')
  const [language, setLanguage] = useState<Language>('zh');
  const text = translations[language];

  // Initialize Session
  useEffect(() => {

    // --- STEP 1: VERSION CHECK ---
    // This runs immediately. If update is found, it reloads the page before app initializes.
    checkAndEnforceVersion();

    // Timer to show the "Reset" button if loading takes too long (e.g. > 4 seconds)
    const resetTimer = setTimeout(() => {
        if (isLoading) setShowResetButton(true);
    }, 4000);

    const initApp = async () => {
        // SAFETY TIMEOUT: Force loading to stop after 7 seconds max
        const timeoutPromise = new Promise((_, reject) => 
            setTimeout(() => reject(new Error("Initialization timed out")), 7000)
        );

        const sessionPromise = async () => {
            const { data, error } = await supabase.auth.getSession();
            if (error) throw error;

            if (data?.session) {
                await loadUserData(data.session.user.id, data.session.user.email || '');
            } else {
                setView(AppView.ONBOARDING);
            }
        };

        try {
            await Promise.race([sessionPromise(), timeoutPromise]);
        } catch (error) {
            console.warn("App Initialization fallback:", error);
            // If anything fails or times out, default to Onboarding so user isn't stuck
            if (!userId) setView(AppView.ONBOARDING);
        } finally {
            setIsLoading(false);
            clearTimeout(resetTimer);
        }
    };

    initApp();

    // 2. Listen for Auth Changes (Password Recovery / Login / Logout)
    const { data: authListener } = supabase.auth.onAuthStateChange(async (event, session) => {
        if (event === 'PASSWORD_RECOVERY') {
            setIsRecoveryMode(true);
            setView(AppView.PROFILE); // Direct user to profile to change password
            setIsLoading(false);
        } else if (event === 'SIGNED_IN' && session) {
             // Only reload if we aren't already loaded (prevents double firing)
             if (!userId) {
                await loadUserData(session.user.id, session.user.email || '');
             }
        } else if (event === 'SIGNED_OUT') {
            setUser(null);
            setUserId(null);
            setHistory([]);
            setCurrentAnalysis(null);
            setView(AppView.ONBOARDING);
            setIsRecoveryMode(false);
            setIsLoading(false);
        }
    });

    return () => {
        authListener.subscription.unsubscribe();
        clearTimeout(resetTimer);
    };
  }, []);

  // Helper to calculate XP/Level from history list
  const calculateGamification = (historyList: AIAnalysis[]) => {
      let totalXP = 0;
      historyList.forEach(item => {
          const wordCount = item.transcript ? item.transcript.split(' ').length : 0;
          // Formula: Score + (Words * 0.5)
          // Rewards length/effort even if score is low
          totalXP += Math.round(item.score + (wordCount * 0.5));
      });

      // PROGRESSIVE LEVELING FORMULA
      // Level 1 -> 2: 300 XP
      // Increase by 500 XP per level until Cap of 3000 XP

      let level = 1;
      let costForNext = 300;
      let remainingXP = totalXP;

      while (remainingXP >= costForNext) {
          remainingXP -= costForNext;
          level++;

          // Progressive Increase
          costForNext += 500;

          // Cap at 3000
          if (costForNext > 3000) costForNext = 3000;
      }

      return { totalXP, level };
  };

  const loadUserData = async (uid: string, email: string) => {
    try {
      setUserId(uid);

      // 1. Fetch Profile (Base Data)
      let profileBase = { name: 'Student', streak: 0, lastRecordingDate: null as string | null };

      const { data: profileData, error: profileError } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', uid)
        .single();

      if (!profileError && profileData) {
        profileBase = {
            name: profileData.name,
            streak: profileData.streak || 0,
            lastRecordingDate: profileData.last_recording_date
        };
      } else {
          // Fallback if profile missing
          const { data: { user: authUser } } = await supabase.auth.getUser();
          profileBase.name = authUser?.user_metadata?.name || 'Student';
      }

      // 2. Fetch History
      const { data: historyData, error: historyError } = await supabase
        .from('history')
        .select('*')
        .eq('user_id', uid)
        .order('created_at', { ascending: true });

      let loadedHistory: AIAnalysis[] = [];
      if (!historyError && historyData) {
        loadedHistory = historyData.map((h: any) => ({
          transcript: h.transcript,
          score: h.score,
          grammarScore: h.grammar_score,
          pronunciationScore: h.pronunciation_score,
          fluencyScore: h.fluency_score,
          vocabularyScore: h.vocabulary_score,
          feedback: h.feedback || [], 
          tips: h.tips || [], 
          encouragement: h.encouragement,
          timestamp: h.created_at
        }));
        setHistory(loadedHistory);
      }

      // 3. Calculate Dynamic XP/Level
      const { totalXP, level } = calculateGamification(loadedHistory);

      setUser({
        name: profileBase.name,
        email: email,
        streak: profileBase.streak,
        lastRecordingDate: profileBase.lastRecordingDate,
        xp: totalXP,
        level: level
      });

      // Only go to dashboard if NOT in recovery mode
      if (!isRecoveryMode) {
          setView(AppView.DASHBOARD);
      }
    } catch (e) {
      console.error("Error loading user data", e);
      // If error occurs but session exists, we should probably still show dashboard or handle gracefully
    } finally {
      setIsLoading(false);
    }
  };

  // Handle Authentication (Login/Signup)
  const handleAuth = async (email: string, password: string, name: string, mode: 'LOGIN' | 'SIGNUP') => {
    setIsLoading(true);
    try {
      if (mode === 'SIGNUP') {
        const { data, error } = await supabase.auth.signUp({ 
            email, 
            password,
            options: {
                data: { name: name } // Store name in metadata as backup
            }
        });

        if (error) throw error;

        // CRITICAL: Check if session exists. 
        if (data.user && !data.session) {
            alert("Registration successful! Please check your email to verify your account before logging in.");
            setIsLoading(false);
            return; 
        }

        if (data.user && data.session) {
          // Create Profile Row immediately if we have a session
          const { error: profileError } = await supabase.from('profiles').insert({
            id: data.user.id,
            email: email,
            name: name,
            streak: 0,
            last_recording_date: null
          });

          if (profileError) {
              console.error("Profile creation warning:", profileError);
          }

          await loadUserData(data.user.id, email);
        }
      } else {
        // Login
        const { data, error } = await supabase.auth.signInWithPassword({ email, password });
        if (error) throw error;
        if (data.user) {
          await loadUserData(data.user.id, email);
        }
      }
    } catch (error: any) {
      // Suppress console.error for auth failures to prevent alarm
      setIsLoading(false);
      // Re-throw so component can handle UI message
      throw error;
    }
  };

  const handleResetPassword = async (email: string) => {
      // DYNAMIC URL FIX:
      // Uses window.location.origin to work on both Dev and Production (Cloud Run)
      const redirectUrl = window.location.origin;

      const { error } = await supabase.auth.resetPasswordForEmail(email, {
          redirectTo: redirectUrl,
      });
      if (error) throw error;
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setUserId(null);
    setUser(null);
    setHistory([]);
    setCurrentAnalysis(null);
    setView(AppView.ONBOARDING);
  };

  const handleUpdateProfile = async (newName: string, currentPassword?: string, newPassword?: string) => {
    if (!user || !userId) return;

    try {
      // 1. Update Profile Table
      const { error: updateError } = await supabase
        .from('profiles')
        .update({ name: newName })
        .eq('id', userId);

      if (updateError) throw updateError;

      // 2. Update Password (if provided)
      if (newPassword) {
        // If NOT in recovery mode, we MUST verify the old password first for security.
        if (!isRecoveryMode && currentPassword) {
            const { error: verifyError } = await supabase.auth.signInWithPassword({
                email: user.email,
                password: currentPassword
            });

            if (verifyError) {
                throw new Error("Incorrect current password. Cannot update password.");
            }
        }

        // Update to new password
        const { error: pwError } = await supabase.auth.updateUser({ password: newPassword });
        if (pwError) throw pwError;

        // If successful, exit recovery mode
        if (isRecoveryMode) {
            setIsRecoveryMode(false);
            alert("Password updated successfully! Redirecting to Dashboard.");
            setView(AppView.DASHBOARD);
            return; // Exit early to avoid double alert
        }
      }

      // Update Local State (preserve XP/Level)
      setUser({ ...user, name: newName });

    } catch (error: any) {
      console.error("Update failed", error);
      throw error; 
    }
  };

  const handleStartRecording = () => {
    setView(AppView.RECORDING);
  };

  // NOTE: Changed to async and removed internal try/catch logic to allow errors 
  // to propagate to the AudioRecorder component for display.
  const handleAnalyze = async (audioBase64: string, duration: number, mimeType: string) => {
    if (!user || !userId) return;

    setIsAnalyzing(true);
    try {
      // Pass language to Gemini
      const analysis = await analyzeAudio(audioBase64, duration, mimeType, language);

      // Update Streak logic
      const today = new Date().toDateString();
      const lastDate = user.lastRecordingDate ? new Date(user.lastRecordingDate).toDateString() : null;
      const isoTimestamp = new Date().toISOString();

      let newStreak = user.streak;
      if (lastDate !== today) {
          newStreak = user.streak + 1;
      }

      // 1. Save to History DB
      const { error: historyError } = await supabase.from('history').insert({
        user_id: userId,
        transcript: analysis.transcript,
        score: analysis.score,
        grammar_score: analysis.grammarScore,
        pronunciation_score: analysis.pronunciationScore,
        fluency_score: analysis.fluencyScore,
        vocabulary_score: analysis.vocabularyScore,
        feedback: analysis.feedback || [], 
        tips: analysis.tips || [], 
        encouragement: analysis.encouragement,
        created_at: isoTimestamp
      });

      if (historyError) {
          // If error is related to response size, log it but don't crash app if possible
          console.error("Failed to save history:", historyError.message);
      }

      // 2. Update Profile DB (Streak only)
      const { error: profileError } = await supabase
        .from('profiles')
        .upsert({ 
          id: userId,
          name: user.name,
          email: user.email,
          streak: newStreak, 
          last_recording_date: isoTimestamp 
        });

      if (profileError) console.error("Failed to update streak", profileError);

      // 3. Update Local State (Recalculate XP)
      analysis.timestamp = isoTimestamp;
      const newHistory = [...history, analysis];
      const { totalXP, level } = calculateGamification(newHistory);

      setUser({
          ...user,
          streak: newStreak,
          lastRecordingDate: isoTimestamp,
          xp: totalXP,
          level: level
      });

      setCurrentAnalysis(analysis);
      setHistory(newHistory);

      setView(AppView.ANALYSIS);
    } catch (error: any) {
      console.error("Analysis Error in App:", error);
      // Re-throw so AudioRecorder can catch and display
      throw error;
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleCloseFeedback = () => {
    setCurrentAnalysis(null);
    setView(AppView.DASHBOARD);
  };

  const handleViewHistory = (analysis: AIAnalysis) => {
    setCurrentAnalysis(analysis);
    setView(AppView.ANALYSIS);
  };

  // Manual Hard Reset for "Stuck" scenarios
  const handleManualReset = () => {
      // Clear all local storage to remove potentially corrupt tokens
      localStorage.clear();
      // Force reload the page
      window.location.reload();
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-black flex flex-col items-center justify-center gap-6 p-4 text-center">
        <div className="text-blue-500 animate-pulse text-xl font-serif">Loading Global Voice Club...</div>

        {showResetButton && (
            <div className="animate-fade-in flex flex-col items-center">
                <p className="text-gray-500 text-sm mb-3">Taking longer than usual?</p>
                <button 
                    onClick={handleManualReset}
                    className="px-4 py-2 bg-gray-800 border border-gray-600 rounded-lg text-white hover:bg-gray-700 hover:border-white transition-all flex items-center gap-2 text-sm"
                >
                    <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-4 h-4">
                        <path strokeLinecap="round" strokeLinejoin="round" d="M16.023 9.348h4.992v-.001M2.985 19.644v-4.992m0 0h4.992m-4.993 0 3.181 3.183a8.25 8.25 0 0 0 13.803-3.7M4.031 9.865a8.25 8.25 0 0 1 13.803-3.7l3.181 3.182m0-4.991v4.99" />
                    </svg>
                    Refresh & Fix
                </button>
            </div>
        )}
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-black text-white font-sans selection:bg-blue-600 selection:text-white overflow-x-hidden w-full flex flex-col">
      <Header 
        user={user} 
        text={text}
        language={language}
        version={UI_VERSION}
        onToggleLanguage={() => setLanguage(l => l === 'en' ? 'zh' : 'en')}
        onLogout={handleLogout} 
        onProfileClick={() => setView(AppView.PROFILE)}
        onLogoClick={() => setView(AppView.DASHBOARD)}
      />

      {/* 
        LAYOUT FIX: 
        Replaced 'container' and 'max-w-full' with an explicit centered container.
        This fixes the off-center issue on mobile devices.
      */}
      <main className="w-full max-w-[95%] 2xl:max-w-[1800px] mx-auto px-4 md:px-8 pt-6 pb-12 flex-grow">
        {view === AppView.ONBOARDING && (
          <Onboarding 
            onAuth={handleAuth} 
            onResetPassword={handleResetPassword}
            text={text}
          />
        )}

        {view === AppView.DASHBOARD && user && (
          <Dashboard 
            user={user} 
            history={history} 
            onStartRecording={handleStartRecording}
            onViewHistory={handleViewHistory}
            text={text}
          />
        )}

        {view === AppView.PROFILE && user && (
            <Profile 
                user={user}
                history={history}
                onUpdateProfile={handleUpdateProfile}
                onBack={() => setView(AppView.DASHBOARD)}
                text={text}
                isRecoveryMode={isRecoveryMode}
            />
        )}

        {view === AppView.RECORDING && (
          <AudioRecorder 
            onAnalyze={handleAnalyze} 
            isAnalyzing={isAnalyzing}
            onBack={() => setView(AppView.DASHBOARD)}
            text={text}
          />
        )}

        {view === AppView.ANALYSIS && currentAnalysis && user && (
          <FeedbackDisplay 
            analysis={currentAnalysis} 
            userName={user.name}
            userEmail={user.email}
            onClose={handleCloseFeedback}
            text={text}
          />
        )}
      </main>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type, Schema, HarmCategory, HarmBlockThreshold } from "@google/genai";
import { AIAnalysis, FeedbackItem } from "../types";

// Critical: Check API Key immediately
if (!process.env.API_KEY) {
    console.error("CRITICAL ERROR: API_KEY is missing from environment variables.");
}

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

// --- SCHEMAS ---

const analysisSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    score: { type: Type.NUMBER, description: "Score 0-100" },
    grammarScore: { type: Type.NUMBER, description: "Grammar 0-100" },
    pronunciationScore: { type: Type.NUMBER, description: "Pronun 0-100" },
    fluencyScore: { type: Type.NUMBER, description: "Fluency 0-100" },
    vocabularyScore: { type: Type.NUMBER, description: "Vocab 0-100" },
    feedback: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          original: { type: Type.STRING },
          correction: { type: Type.STRING },
          explanation: { type: Type.STRING },
        },
        required: ["original", "correction", "explanation"]
      }
    },
    tips: { type: Type.ARRAY, items: { type: Type.STRING } },
    encouragement: { type: Type.STRING },
    transcript: { type: Type.STRING }
  },
  required: ["score", "grammarScore", "pronunciationScore", "fluencyScore", "vocabularyScore", "feedback", "tips", "encouragement", "transcript"],
};

// --- HELPERS ---

// Robust fallback generator to ensure the promise ALWAYS resolves
const generateFallbackAnalysis = (reason: string): AIAnalysis => {
    console.warn("Generating Fallback Analysis. Reason:", reason);

    // Generate 10 generic feedback items to satisfy existing constraints
    const feedback = Array(10).fill(null).map((_, i) => ({
        original: i === 0 ? "(Audio processing delay)" : "...",
        correction: i === 0 ? "Please try a shorter recording" : "...",
        explanation: "The AI analysis took too long to complete. We've saved your session, but detailed feedback is unavailable."
    }));

    return {
        score: 75, 
        grammarScore: 75,
        pronunciationScore: 75,
        fluencyScore: 75,
        vocabularyScore: 75,
        feedback,
        tips: [
            "Ensure you have a stable internet connection.",
            "Try keeping recordings under 2 minutes for faster results.",
            "Speak clearly and close to the microphone.",
            "Reduce background noise.",
            "Practice regularly to improve speed."
        ],
        encouragement: "Good effort! The system timed out, but keep practicing!",
        transcript: "(Transcript unavailable due to timeout)",
        timestamp: new Date().toISOString()
    };
};

const safeJSONParse = (text: string): any => {
    if (!text) throw new Error("Empty JSON text");

    // Safety: Prevent massive string parsing lockups
    if (text.length > 50000) {
        text = text.substring(0, 50000); 
    }

    try {
        return JSON.parse(text);
    } catch (e) {
        // Cleanup Markdown
        const clean = text.replace(/```json/g, '').replace(/```/g, '').trim();
        try {
            return JSON.parse(clean);
        } catch (e2) {
            // Aggressive Repair: Find outer brackets
            const first = clean.indexOf('{');
            const last = clean.lastIndexOf('}');
            if (first !== -1 && last !== -1) {
                try {
                     return JSON.parse(clean.substring(first, last + 1));
                } catch (e3) {
                    throw new Error("JSON Parse Failed");
                }
            }
            throw new Error("Invalid JSON structure");
        }
    }
};

const normalizeFeedback = (rawFeedback: any): FeedbackItem[] => {
    const safeList: FeedbackItem[] = Array.isArray(rawFeedback)
        ? rawFeedback
            .map((item: any) => ({
                original: String(item?.original || "").trim(),
                correction: String(item?.correction || "").trim(),
                explanation: String(item?.explanation || "").trim()
            }))
            .filter(item => item.original && item.correction)
        : [];

    const trimmed = safeList.slice(0, 10);

    const paddingPool: FeedbackItem[] = [
        { original: "(Volume)", correction: "Speak louder.", explanation: "Maintain steady volume." },
        { original: "(Pacing)", correction: "Slow down.", explanation: "Rushing causes slurred words." },
        { original: "(Completeness)", correction: "Finish sentences.", explanation: "Avoid trailing off." },
        { original: "(Clarity)", correction: "Enunciate clearly.", explanation: "Vowel sounds were muddy." },
        { original: "(Grammar)", correction: "Check verb tense.", explanation: "Ensure verbs match time." },
        { original: "(Intonation)", correction: "Use rising tone?", explanation: "Pitch was too flat." },
        { original: "(Structure)", correction: "Shorten sentences.", explanation: "Long sentences lose clarity." },
        { original: "(Confidence)", correction: "Project voice.", explanation: "Confidence improves fluency." },
        { original: "(Diction)", correction: "Hit consonants.", explanation: "Endings were soft." },
        { original: "(Flow)", correction: "Use connectors.", explanation: "Link ideas with 'and/but'." }
    ];

    let poolIndex = 0;
    while (trimmed.length < 10) {
        trimmed.push(paddingPool[poolIndex % paddingPool.length]);
        poolIndex++;
    }

    return trimmed;
};

const generateRequest = async (
    modelName: string,
    contents: any,
    schema: Schema,
    timeoutMs: number,
    systemInstruction?: string
): Promise<any> => {
    const controller = new AbortController();

    // Internal safety timeout for the fetch
    const timeoutPromise = new Promise((_, reject) => 
        setTimeout(() => {
            controller.abort(); 
            reject(new Error("API_TIMEOUT"));
        }, timeoutMs)
    );

    try {
        const apiPromise = ai.models.generateContent({
            model: modelName,
            contents: contents,
            config: {
                responseMimeType: "application/json",
                responseSchema: schema,
                systemInstruction: systemInstruction,
                maxOutputTokens: 2048, // Reduced to ensure fast completion
                temperature: 0.2, 
                safetySettings: [
                     { category: HarmCategory.HARM_CATEGORY_HATE_SPEECH, threshold: HarmBlockThreshold.BLOCK_NONE },
                     { category: HarmCategory.HARM_CATEGORY_SEXUALLY_EXPLICIT, threshold: HarmBlockThreshold.BLOCK_NONE },
                     { category: HarmCategory.HARM_CATEGORY_DANGEROUS_CONTENT, threshold: HarmBlockThreshold.BLOCK_NONE },
                     { category: HarmCategory.HARM_CATEGORY_HARASSMENT, threshold: HarmBlockThreshold.BLOCK_NONE }
                ]
            }
        });

        // Race: API vs Timeout
        const result: any = await Promise.race([apiPromise, timeoutPromise]);

        let responseText = result?.text;
        const candidate = result?.candidates?.[0];

        // Fallback text extraction
        if (!responseText && candidate?.content?.parts) {
             responseText = candidate.content.parts.map((p: any) => p.text).join('');
        }

        if (!responseText) throw new Error("EMPTY_RESPONSE");

        return safeJSONParse(responseText);

    } catch (error: any) {
        if (error.message === 'API_TIMEOUT') throw error;
        // Map other API errors to be cleaner
        console.warn("AI Raw Error:", error);
        throw new Error("API_ERROR");
    }
};

export const analyzeAudio = async (base64Audio: string, duration: number, mimeType: string, language: 'en' | 'zh'): Promise<AIAnalysis> => {

    // --- SLA CONFIGURATION ---
    // Target: 60s total. 
    // We set backend timeout to 55s to ensure we return *something* to the frontend before its 100s watchdog.
    const SLA_TIMEOUT_MS = 55000; 

    if (!base64Audio || base64Audio.length < 100) throw new Error("Audio is empty.");
    // 15MB limit
    if (base64Audio.length > 15 * 1024 * 1024) throw new Error("File too large (>15MB).");

    let langContext = "Role: English Teacher. Output: JSON. Language: English."; 
    if (language === 'zh') {
        langContext = "Role: ESL Teacher. Output: JSON. Language: Explanations in Traditional Chinese, Corrections in English.";
    }

    // Minimized Prompt for Speed
    const promptInstructions = `
    Task: Analyze audio.
    1. Transcribe speech.
    2. Score (0-100).
    3. 10 corrections.
    4. 5 tips.
    Output JSON.
    `;

    // --- FAIL-SAFE RACE CONDITION ---
    // If 'logicPromise' takes longer than SLA_TIMEOUT_MS, 'timeoutPromise' wins and returns a Fallback Report.

    const logicPromise = async () => {
        const result = await generateRequest(
            'gemini-2.5-flash', 
            {
                parts: [
                    { inlineData: { data: base64Audio, mimeType: mimeType } },
                    { text: promptInstructions }
                ]
            },
            analysisSchema,
            SLA_TIMEOUT_MS - 2000, // Inner timeout slightly shorter
            langContext
        );

        return {
            ...result,
            feedback: normalizeFeedback(result.feedback),
            tips: Array.isArray(result.tips) ? result.tips.slice(0, 5) : [],
            transcript: result.transcript || "(No transcript)",
            timestamp: new Date().toISOString()
        } as AIAnalysis;
    };

    const timeoutPromise = new Promise<AIAnalysis>((resolve) => {
        setTimeout(() => {
            resolve(generateFallbackAnalysis("Timeout (55s Limit Reached)"));
        }, SLA_TIMEOUT_MS);
    });

    try {
        console.log(`Starting Analysis (Fail-Safe Mode). Size: ${(base64Audio.length/1024/1024).toFixed(2)}MB`);
        return await Promise.race([logicPromise(), timeoutPromise]);
    } catch (error: any) {
        console.error("Analysis Exception:", error);
        return generateFallbackAnalysis(error.message || "Unknown Error");
    }
};

import React, { useState, useEffect } from 'react';
import { UserProfile, AIAnalysis, AppView, Language } from './types';
import Header from './components/Header';
import Onboarding from './components/Onboarding';
import AudioRecorder from './components/AudioRecorder';
import FeedbackDisplay from './components/FeedbackDisplay';
import Dashboard from './components/Dashboard';
import Profile from './components/Profile';
import { analyzeAudio } from './services/geminiService';
import { supabase } from './services/supabaseClient';
import { translations } from './utils/translations';
import { checkAndEnforceVersion } from './utils/versionManager';

// We now read the version from the manifest via the manager, 
// but we keep this for the UI display.
// IMPORTANT: Update 'version.json' when you update this!
const UI_VERSION = '1.0.52'; 

const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [userId, setUserId] = useState<string | null>(null); // Supabase Auth ID
  const [view, setView] = useState<AppView>(AppView.ONBOARDING);
  const [history, setHistory] = useState<AIAnalysis[]>([]);
  const [currentAnalysis, setCurrentAnalysis] = useState<AIAnalysis | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [showResetButton, setShowResetButton] = useState(false); // Fail-safe button

  // Recovery Mode State (For Password Reset)
  const [isRecoveryMode, setIsRecoveryMode] = useState(false);

  // Language State - Default to Traditional Chinese ('zh')
  const [language, setLanguage] = useState<Language>('zh');
  const text = translations[language];

  // Initialize Session
  useEffect(() => {

    // --- STEP 1: VERSION CHECK ---
    checkAndEnforceVersion();

    // Timer to show the "Reset" button if loading takes too long
    const resetTimer = setTimeout(() => {
        if (isLoading) setShowResetButton(true);
    }, 4000);

    const initApp = async () => {
        // SAFETY TIMEOUT: Force loading to stop after 7 seconds max
        const timeoutPromise = new Promise((_, reject) => 
            setTimeout(() => reject(new Error("Initialization timed out")), 7000)
        );

        const sessionPromise = async () => {
            const { data, error } = await supabase.auth.getSession();
            if (error) throw error;

            if (data?.session) {
                await loadUserData(data.session.user.id, data.session.user.email || '');
            } else {
                setView(AppView.ONBOARDING);
            }
        };

        try {
            await Promise.race([sessionPromise(), timeoutPromise]);
        } catch (error) {
            console.warn("App Initialization fallback:", error);
            if (!userId) setView(AppView.ONBOARDING);
        } finally {
            setIsLoading(false);
            clearTimeout(resetTimer);
        }
    };

    initApp();

    const { data: authListener } = supabase.auth.onAuthStateChange(async (event, session) => {
        if (event === 'PASSWORD_RECOVERY') {
            setIsRecoveryMode(true);
            setView(AppView.PROFILE); 
            setIsLoading(false);
        } else if (event === 'SIGNED_IN' && session) {
             if (!userId) {
                await loadUserData(session.user.id, session.user.email || '');
             }
        } else if (event === 'SIGNED_OUT') {
            setUser(null);
            setUserId(null);
            setHistory([]);
            setCurrentAnalysis(null);
            setView(AppView.ONBOARDING);
            setIsRecoveryMode(false);
            setIsLoading(false);
        }
    });

    return () => {
        authListener.subscription.unsubscribe();
        clearTimeout(resetTimer);
    };
  }, []);

  // Helper to calculate XP/Level from history list
  const calculateGamification = (historyList: AIAnalysis[]) => {
      let totalXP = 0;
      historyList.forEach(item => {
          const wordCount = item.transcript ? item.transcript.split(' ').length : 0;
          totalXP += Math.round(item.score + (wordCount * 0.5));
      });

      let level = 1;
      let costForNext = 300;
      let remainingXP = totalXP;

      while (remainingXP >= costForNext) {
          remainingXP -= costForNext;
          level++;
          costForNext += 500;
          if (costForNext > 3000) costForNext = 3000;
      }

      return { totalXP, level };
  };

  const loadUserData = async (uid: string, email: string) => {
    try {
      setUserId(uid);

      let profileBase = { name: 'Student', streak: 0, lastRecordingDate: null as string | null };

      const { data: profileData } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', uid)
        .single();

      if (profileData) {
        profileBase = {
            name: profileData.name,
            streak: profileData.streak || 0,
            lastRecordingDate: profileData.last_recording_date
        };
      } else {
          const { data: { user: authUser } } = await supabase.auth.getUser();
          profileBase.name = authUser?.user_metadata?.name || 'Student';
      }

      const { data: historyData } = await supabase
        .from('history')
        .select('*')
        .eq('user_id', uid)
        .order('created_at', { ascending: true });

      let loadedHistory: AIAnalysis[] = [];
      if (historyData) {
        loadedHistory = historyData.map((h: any) => ({
          transcript: h.transcript,
          score: h.score,
          grammarScore: h.grammar_score,
          pronunciationScore: h.pronunciation_score,
          fluencyScore: h.fluency_score,
          vocabularyScore: h.vocabulary_score,
          feedback: h.feedback || [], 
          tips: h.tips || [], 
          encouragement: h.encouragement,
          timestamp: h.created_at
        }));
        setHistory(loadedHistory);
      }

      const { totalXP, level } = calculateGamification(loadedHistory);

      setUser({
        name: profileBase.name,
        email: email,
        streak: profileBase.streak,
        lastRecordingDate: profileBase.lastRecordingDate,
        xp: totalXP,
        level: level
      });

      if (!isRecoveryMode) {
          setView(AppView.DASHBOARD);
      }
    } catch (e) {
      console.error("Error loading user data", e);
    } finally {
      setIsLoading(false);
    }
  };

  const handleAuth = async (email: string, password: string, name: string, mode: 'LOGIN' | 'SIGNUP') => {
    setIsLoading(true);
    try {
      if (mode === 'SIGNUP') {
        const { data, error } = await supabase.auth.signUp({ 
            email, 
            password,
            options: { data: { name: name } }
        });

        if (error) throw error;

        if (data.user && !data.session) {
            alert("Registration successful! Please check your email to verify your account before logging in.");
            setIsLoading(false);
            return; 
        }

        if (data.user && data.session) {
          await supabase.from('profiles').insert({
            id: data.user.id,
            email: email,
            name: name,
            streak: 0,
            last_recording_date: null
          });
          await loadUserData(data.user.id, email);
        }
      } else {
        const { data, error } = await supabase.auth.signInWithPassword({ email, password });
        if (error) throw error;
        if (data.user) {
          await loadUserData(data.user.id, email);
        }
      }
    } catch (error: any) {
      setIsLoading(false);
      throw error;
    }
  };

  const handleResetPassword = async (email: string) => {
      const redirectUrl = window.location.origin;
      const { error } = await supabase.auth.resetPasswordForEmail(email, {
          redirectTo: redirectUrl,
      });
      if (error) throw error;
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setUserId(null);
    setUser(null);
    setHistory([]);
    setCurrentAnalysis(null);
    setView(AppView.ONBOARDING);
  };

  const handleUpdateProfile = async (newName: string, currentPassword?: string, newPassword?: string) => {
    if (!user || !userId) return;

    try {
      const { error: updateError } = await supabase
        .from('profiles')
        .update({ name: newName })
        .eq('id', userId);

      if (updateError) throw updateError;

      if (newPassword) {
        if (!isRecoveryMode && currentPassword) {
            const { error: verifyError } = await supabase.auth.signInWithPassword({
                email: user.email,
                password: currentPassword
            });
            if (verifyError) throw new Error("Incorrect current password.");
        }
        const { error: pwError } = await supabase.auth.updateUser({ password: newPassword });
        if (pwError) throw pwError;

        if (isRecoveryMode) {
            setIsRecoveryMode(false);
            alert("Password updated successfully! Redirecting to Dashboard.");
            setView(AppView.DASHBOARD);
            return; 
        }
      }

      setUser({ ...user, name: newName });
    } catch (error: any) {
      console.error("Update failed", error);
      throw error; 
    }
  };

  const handleStartRecording = () => {
    setView(AppView.RECORDING);
  };

  // --- ANALYSIS HANDLER (OPTIMIZED) ---
  const handleAnalyze = async (audioBase64: string, duration: number, mimeType: string) => {
    if (!user || !userId) return;

    setIsAnalyzing(true);
    try {
      // 1. Get Analysis from AI
      const analysis = await analyzeAudio(audioBase64, duration, mimeType, language);

      // 2. Prepare Optimistic UI Data
      const today = new Date().toDateString();
      const lastDate = user.lastRecordingDate ? new Date(user.lastRecordingDate).toDateString() : null;
      const isoTimestamp = new Date().toISOString();
      analysis.timestamp = isoTimestamp;

      let newStreak = user.streak;
      if (lastDate !== today) {
          newStreak = user.streak + 1;
      }

      const newHistory = [...history, analysis];
      const { totalXP, level } = calculateGamification(newHistory);

      // 3. UPDATE UI IMMEDIATELY (Do NOT wait for DB)
      // This prevents the "Finalizing..." stall if DB is slow.
      setUser({
          ...user,
          streak: newStreak,
          lastRecordingDate: isoTimestamp,
          xp: totalXP,
          level: level
      });
      setCurrentAnalysis(analysis);
      setHistory(newHistory);

      // UNMOUNT RECORDER NOW
      setView(AppView.ANALYSIS);
      setIsAnalyzing(false);

      // 4. SAVE TO DB IN BACKGROUND (Fire & Forget)
      // We do not await this, so the UI is already responsive.
      (async () => {
          try {
              // Save History
              const { error: histError } = await supabase.from('history').insert({
                user_id: userId,
                transcript: analysis.transcript,
                score: analysis.score,
                grammar_score: analysis.grammarScore,
                pronunciation_score: analysis.pronunciationScore,
                fluency_score: analysis.fluencyScore,
                vocabulary_score: analysis.vocabularyScore,
                feedback: analysis.feedback || [], 
                tips: analysis.tips || [], 
                encouragement: analysis.encouragement,
                created_at: isoTimestamp
              });
              if (histError) console.error("Background Save History Failed:", histError);

              // Update Profile
              const { error: profError } = await supabase.from('profiles').upsert({ 
                  id: userId,
                  name: user.name,
                  email: user.email,
                  streak: newStreak, 
                  last_recording_date: isoTimestamp 
              });
              if (profError) console.error("Background Save Profile Failed:", profError);
          } catch (dbErr) {
              console.error("Background DB Error:", dbErr);
          }
      })();

    } catch (error: any) {
      console.error("Analysis Error in App:", error);
      setIsAnalyzing(false);
      throw error; // Pass back to AudioRecorder to show error
    }
  };

  const handleCloseFeedback = () => {
    setCurrentAnalysis(null);
    setView(AppView.DASHBOARD);
  };

  const handleViewHistory = (analysis: AIAnalysis) => {
    setCurrentAnalysis(analysis);
    setView(AppView.ANALYSIS);
  };

  const handleManualReset = () => {
      localStorage.clear();
      window.location.reload();
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-black flex flex-col items-center justify-center gap-6 p-4 text-center">
        <div className="text-blue-500 animate-pulse text-xl font-serif">Loading Global Voice Club...</div>
        {showResetButton && (
            <div className="animate-fade-in flex flex-col items-center">
                <button 
                    onClick={handleManualReset}
                    className="px-4 py-2 bg-gray-800 border border-gray-600 rounded-lg text-white text-sm"
                >
                    Refresh & Fix
                </button>
            </div>
        )}
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-black text-white font-sans selection:bg-blue-600 selection:text-white overflow-x-hidden w-full flex flex-col">
      <Header 
        user={user} 
        text={text}
        language={language}
        version={UI_VERSION}
        onToggleLanguage={() => setLanguage(l => l === 'en' ? 'zh' : 'en')}
        onLogout={handleLogout} 
        onProfileClick={() => setView(AppView.PROFILE)}
        onLogoClick={() => setView(AppView.DASHBOARD)}
      />
      <main className="w-full max-w-[95%] 2xl:max-w-[1800px] mx-auto px-4 md:px-8 pt-6 pb-12 flex-grow">
        {view === AppView.ONBOARDING && (
          <Onboarding onAuth={handleAuth} onResetPassword={handleResetPassword} text={text} />
        )}
        {view === AppView.DASHBOARD && user && (
          <Dashboard user={user} history={history} onStartRecording={handleStartRecording} onViewHistory={handleViewHistory} text={text} />
        )}
        {view === AppView.PROFILE && user && (
            <Profile user={user} history={history} onUpdateProfile={handleUpdateProfile} onBack={() => setView(AppView.DASHBOARD)} text={text} isRecoveryMode={isRecoveryMode} />
        )}
        {view === AppView.RECORDING && (
          <AudioRecorder onAnalyze={handleAnalyze} isAnalyzing={isAnalyzing} onBack={() => setView(AppView.DASHBOARD)} text={text} />
        )}
        {view === AppView.ANALYSIS && currentAnalysis && user && (
          <FeedbackDisplay analysis={currentAnalysis} userName={user.name} userEmail={user.email} onClose={handleCloseFeedback} text={text} />
        )}
      </main>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type, Schema, HarmCategory, HarmBlockThreshold } from "@google/genai";
import { AIAnalysis, FeedbackItem } from "../types";

// Critical: Check API Key immediately
if (!process.env.API_KEY) {
    console.error("CRITICAL ERROR: API_KEY is missing from environment variables.");
}

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

// --- SCHEMAS ---

const analysisSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    score: { type: Type.NUMBER, description: "Score 0-100" },
    grammarScore: { type: Type.NUMBER, description: "Grammar 0-100" },
    pronunciationScore: { type: Type.NUMBER, description: "Pronun 0-100" },
    fluencyScore: { type: Type.NUMBER, description: "Fluency 0-100" },
    vocabularyScore: { type: Type.NUMBER, description: "Vocab 0-100" },
    feedback: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          original: { type: Type.STRING },
          correction: { type: Type.STRING },
          explanation: { type: Type.STRING },
        },
        required: ["original", "correction", "explanation"]
      }
    },
    tips: { type: Type.ARRAY, items: { type: Type.STRING } },
    encouragement: { type: Type.STRING },
    transcript: { type: Type.STRING }
  },
  required: ["score", "grammarScore", "pronunciationScore", "fluencyScore", "vocabularyScore", "feedback", "tips", "encouragement", "transcript"],
};

// --- HELPERS ---

// Robust fallback generator
const generateFallbackAnalysis = (reason: string, partialData?: Partial<AIAnalysis>): AIAnalysis => {
    console.warn("Generating Fallback Analysis. Reason:", reason);

    // Use partial data if available (e.g. if we extracted a transcript but failed scores)
    const baseScore = partialData?.score || 75;

    const feedback = (partialData?.feedback && partialData.feedback.length > 0) 
        ? partialData.feedback 
        : Array(10).fill(null).map((_, i) => ({
            original: i === 0 ? "(Audio processed partially)" : "...",
            correction: i === 0 ? "Check connection stability" : "...",
            explanation: "The AI analysis encountered an interruption, but we saved your session."
        }));

    return {
        score: baseScore, 
        grammarScore: partialData?.grammarScore || baseScore,
        pronunciationScore: partialData?.pronunciationScore || baseScore,
        fluencyScore: partialData?.fluencyScore || baseScore,
        vocabularyScore: partialData?.vocabularyScore || baseScore,
        feedback,
        tips: partialData?.tips || [
            "Ensure you have a stable internet connection.",
            "Try keeping recordings under 3 minutes for faster results.",
            "Speak clearly and close to the microphone.",
            "Reduce background noise.",
            "Practice regularly to improve speed."
        ],
        encouragement: partialData?.encouragement || "Good effort! We captured your session, though the detailed report is incomplete.",
        transcript: partialData?.transcript || "(Transcript unavailable - Analysis Timeout)",
        timestamp: new Date().toISOString()
    };
};

// Heuristic to repair truncated JSON strings
const repairJSON = (jsonStr: string): string => {
    let repaired = jsonStr.trim();
    // 1. Remove trailing commas
    repaired = repaired.replace(/,\s*([\]}])/g, '$1');

    // 2. Close open strings if cut off
    // Simple check: if odd number of quotes, add one
    const quoteCount = (repaired.match(/"/g) || []).length;
    if (quoteCount % 2 !== 0) {
        repaired += '"';
    }

    // 3. Close open brackets/braces
    const openBraces = (repaired.match(/\{/g) || []).length;
    const closeBraces = (repaired.match(/\}/g) || []).length;
    const openBrackets = (repaired.match(/\[/g) || []).length;
    const closeBrackets = (repaired.match(/\]/g) || []).length;

    if (openBrackets > closeBrackets) repaired += ']'.repeat(openBrackets - closeBrackets);
    if (openBraces > closeBraces) repaired += '}'.repeat(openBraces - closeBraces);

    return repaired;
};

const safeJSONParse = (text: string): any => {
    if (!text) throw new Error("Empty JSON text");

    // Clean Markdown
    let clean = text.replace(/```json/g, '').replace(/```/g, '').trim();

    try {
        return JSON.parse(clean);
    } catch (e) {
        // Attempt Repair
        try {
            const repaired = repairJSON(clean);
            return JSON.parse(repaired);
        } catch (e2) {
             // Aggressive Substring Repair: Find outermost { }
            const first = clean.indexOf('{');
            const last = clean.lastIndexOf('}');
            if (first !== -1 && last !== -1) {
                try {
                     return JSON.parse(clean.substring(first, last + 1));
                } catch (e3) {
                     // Last ditch: Try repairing the substring
                     try {
                        const subRepaired = repairJSON(clean.substring(first));
                        return JSON.parse(subRepaired);
                     } catch (e4) {
                        throw new Error("JSON Parse Failed");
                     }
                }
            }
            throw new Error("Invalid JSON structure");
        }
    }
};

// Fallback: Extract data via Regex if JSON fails
const extractViaRegex = (text: string): Partial<AIAnalysis> => {
    const scoreMatch = text.match(/"score":\s*(\d+)/);
    const transcriptMatch = text.match(/"transcript":\s*"([^"]*)/); // Partial match

    return {
        score: scoreMatch ? parseInt(scoreMatch[1]) : 70,
        transcript: transcriptMatch ? transcriptMatch[1] : "(Recovered text fragment...)"
    };
};

const normalizeFeedback = (rawFeedback: any): FeedbackItem[] => {
    const safeList: FeedbackItem[] = Array.isArray(rawFeedback)
        ? rawFeedback
            .map((item: any) => ({
                original: String(item?.original || "").trim(),
                correction: String(item?.correction || "").trim(),
                explanation: String(item?.explanation || "").trim()
            }))
            .filter(item => item.original && item.correction)
        : [];

    const trimmed = safeList.slice(0, 10);

    const paddingPool: FeedbackItem[] = [
        { original: "(Volume)", correction: "Speak louder.", explanation: "Maintain steady volume." },
        { original: "(Pacing)", correction: "Slow down.", explanation: "Rushing causes slurred words." },
        { original: "(Completeness)", correction: "Finish sentences.", explanation: "Avoid trailing off." },
        { original: "(Clarity)", correction: "Enunciate clearly.", explanation: "Vowel sounds were muddy." },
        { original: "(Grammar)", correction: "Check verb tense.", explanation: "Ensure verbs match time." },
        { original: "(Intonation)", correction: "Use rising tone?", explanation: "Pitch was too flat." },
        { original: "(Structure)", correction: "Shorten sentences.", explanation: "Long sentences lose clarity." },
        { original: "(Confidence)", correction: "Project voice.", explanation: "Confidence improves fluency." },
        { original: "(Diction)", correction: "Hit consonants.", explanation: "Endings were soft." },
        { original: "(Flow)", correction: "Use connectors.", explanation: "Link ideas with 'and/but'." }
    ];

    let poolIndex = 0;
    while (trimmed.length < 10) {
        trimmed.push(paddingPool[poolIndex % paddingPool.length]);
        poolIndex++;
    }

    return trimmed;
};

const generateRequest = async (
    modelName: string,
    contents: any,
    schema: Schema,
    timeoutMs: number,
    systemInstruction?: string
): Promise<any> => {
    const controller = new AbortController();

    const timeoutPromise = new Promise((_, reject) => 
        setTimeout(() => {
            controller.abort(); 
            reject(new Error("API_TIMEOUT"));
        }, timeoutMs)
    );

    try {
        const apiPromise = ai.models.generateContent({
            model: modelName,
            contents: contents,
            config: {
                responseMimeType: "application/json",
                responseSchema: schema,
                systemInstruction: systemInstruction,
                maxOutputTokens: 8192, // Increased for long audio
                temperature: 0.2, 
                safetySettings: [
                     { category: HarmCategory.HARM_CATEGORY_HATE_SPEECH, threshold: HarmBlockThreshold.BLOCK_NONE },
                     { category: HarmCategory.HARM_CATEGORY_SEXUALLY_EXPLICIT, threshold: HarmBlockThreshold.BLOCK_NONE },
                     { category: HarmCategory.HARM_CATEGORY_DANGEROUS_CONTENT, threshold: HarmBlockThreshold.BLOCK_NONE },
                     { category: HarmCategory.HARM_CATEGORY_HARASSMENT, threshold: HarmBlockThreshold.BLOCK_NONE }
                ]
            }
        });

        const result: any = await Promise.race([apiPromise, timeoutPromise]);

        let responseText = result?.text;
        const candidate = result?.candidates?.[0];

        if (!responseText && candidate?.content?.parts) {
             responseText = candidate.content.parts.map((p: any) => p.text).join('');
        }

        if (!responseText) throw new Error("EMPTY_RESPONSE");

        return safeJSONParse(responseText);

    } catch (error: any) {
        if (error.message === 'API_TIMEOUT') throw error;

        // If JSON Parse failed but we have text, try to rescue it via regex in the main handler
        if (error.message === "JSON Parse Failed" || error.message === "Invalid JSON structure") {
            throw error; 
        }

        console.warn("AI Raw Error:", error);
        throw new Error("API_ERROR");
    }
};

export const analyzeAudio = async (base64Audio: string, duration: number, mimeType: string, language: 'en' | 'zh'): Promise<AIAnalysis> => {

    // --- SLA CONFIGURATION ---
    // Increased to 85s for long files. 
    // Frontend watchdog is 100s.
    const SLA_TIMEOUT_MS = 85000; 

    if (!base64Audio || base64Audio.length < 100) throw new Error("Audio is empty.");
    if (base64Audio.length > 15 * 1024 * 1024) throw new Error("File too large (>15MB).");

    let langContext = "Role: English Teacher. Output: JSON. Language: English."; 
    if (language === 'zh') {
        langContext = "Role: ESL Teacher. Output: JSON. Language: Explanations in Traditional Chinese, Corrections in English.";
    }

    // --- OPTIMIZED PROMPT ---
    // Order matters! We ask for scores and feedback FIRST.
    // If tokens run out (MAX_TOKENS), it cuts off the transcript (less critical) 
    // rather than the scores/feedback.
    const promptInstructions = `
    Task: Analyze audio.
    Output JSON object with these keys in this specific order:
    1. score (number)
    2. grammarScore (number)
    3. pronunciationScore (number)
    4. fluencyScore (number)
    5. vocabularyScore (number)
    6. feedback (array of objects: original, correction, explanation)
    7. tips (array of strings)
    8. encouragement (string)
    9. transcript (string) -- Put transcript LAST.
    `;

    const logicPromise = async () => {
        const result = await generateRequest(
            'gemini-2.5-flash', 
            {
                parts: [
                    { inlineData: { data: base64Audio, mimeType: mimeType } },
                    { text: promptInstructions }
                ]
            },
            analysisSchema,
            SLA_TIMEOUT_MS - 2000, 
            langContext
        );

        return {
            ...result,
            feedback: normalizeFeedback(result.feedback),
            tips: Array.isArray(result.tips) ? result.tips.slice(0, 5) : [],
            transcript: result.transcript || "(No transcript)",
            timestamp: new Date().toISOString()
        } as AIAnalysis;
    };

    const timeoutPromise = new Promise<AIAnalysis>((resolve) => {
        setTimeout(() => {
            resolve(generateFallbackAnalysis("Timeout (85s Limit Reached)"));
        }, SLA_TIMEOUT_MS);
    });

    try {
        console.log(`Starting Analysis. Size: ${(base64Audio.length/1024/1024).toFixed(2)}MB`);
        return await Promise.race([logicPromise(), timeoutPromise]);
    } catch (error: any) {
        console.error("Analysis Exception:", error);

        // Final Safety Net: If we have partial data or regex recovery
        // We'll just return the standard fallback for now, but in future could pass partial data here
        return generateFallbackAnalysis(error.message || "Unknown Error");
    }
};

import React, { useState, useEffect } from 'react';
import { UserProfile, AIAnalysis, AppView, Language } from './types';
import Header from './components/Header';
import Onboarding from './components/Onboarding';
import AudioRecorder from './components/AudioRecorder';
import FeedbackDisplay from './components/FeedbackDisplay';
import Dashboard from './components/Dashboard';
import Profile from './components/Profile';
import { analyzeAudio } from './services/geminiService';
import { supabase } from './services/supabaseClient';
import { translations } from './utils/translations';
import { checkAndEnforceVersion } from './utils/versionManager';

// We now read the version from the manifest via the manager, 
// but we keep this for the UI display.
// IMPORTANT: Update 'version.json' when you update this!
const UI_VERSION = '1.0.53'; 

const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [userId, setUserId] = useState<string | null>(null); // Supabase Auth ID
  const [view, setView] = useState<AppView>(AppView.ONBOARDING);
  const [history, setHistory] = useState<AIAnalysis[]>([]);
  const [currentAnalysis, setCurrentAnalysis] = useState<AIAnalysis | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [showResetButton, setShowResetButton] = useState(false); // Fail-safe button

  // Recovery Mode State (For Password Reset)
  const [isRecoveryMode, setIsRecoveryMode] = useState(false);

  // Language State - Default to Traditional Chinese ('zh')
  const [language, setLanguage] = useState<Language>('zh');
  const text = translations[language];

  // Initialize Session
  useEffect(() => {

    // --- STEP 1: VERSION CHECK ---
    checkAndEnforceVersion();

    // Timer to show the "Reset" button if loading takes too long
    const resetTimer = setTimeout(() => {
        if (isLoading) setShowResetButton(true);
    }, 4000);

    const initApp = async () => {
        // SAFETY TIMEOUT: Force loading to stop after 7 seconds max
        const timeoutPromise = new Promise((_, reject) => 
            setTimeout(() => reject(new Error("Initialization timed out")), 7000)
        );

        const sessionPromise = async () => {
            const { data, error } = await supabase.auth.getSession();
            if (error) throw error;

            if (data?.session) {
                await loadUserData(data.session.user.id, data.session.user.email || '');
            } else {
                setView(AppView.ONBOARDING);
            }
        };

        try {
            await Promise.race([sessionPromise(), timeoutPromise]);
        } catch (error) {
            console.warn("App Initialization fallback:", error);
            if (!userId) setView(AppView.ONBOARDING);
        } finally {
            setIsLoading(false);
            clearTimeout(resetTimer);
        }
    };

    initApp();

    const { data: authListener } = supabase.auth.onAuthStateChange(async (event, session) => {
        if (event === 'PASSWORD_RECOVERY') {
            setIsRecoveryMode(true);
            setView(AppView.PROFILE); 
            setIsLoading(false);
        } else if (event === 'SIGNED_IN' && session) {
             if (!userId) {
                await loadUserData(session.user.id, session.user.email || '');
             }
        } else if (event === 'SIGNED_OUT') {
            setUser(null);
            setUserId(null);
            setHistory([]);
            setCurrentAnalysis(null);
            setView(AppView.ONBOARDING);
            setIsRecoveryMode(false);
            setIsLoading(false);
        }
    });

    return () => {
        authListener.subscription.unsubscribe();
        clearTimeout(resetTimer);
    };
  }, []);

  // Helper to calculate XP/Level from history list
  const calculateGamification = (historyList: AIAnalysis[]) => {
      let totalXP = 0;
      historyList.forEach(item => {
          const wordCount = item.transcript ? item.transcript.split(' ').length : 0;
          totalXP += Math.round(item.score + (wordCount * 0.5));
      });

      let level = 1;
      let costForNext = 300;
      let remainingXP = totalXP;

      while (remainingXP >= costForNext) {
          remainingXP -= costForNext;
          level++;
          costForNext += 500;
          if (costForNext > 3000) costForNext = 3000;
      }

      return { totalXP, level };
  };

  const loadUserData = async (uid: string, email: string) => {
    try {
      setUserId(uid);

      let profileBase = { name: 'Student', streak: 0, lastRecordingDate: null as string | null };

      const { data: profileData } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', uid)
        .single();

      if (profileData) {
        profileBase = {
            name: profileData.name,
            streak: profileData.streak || 0,
            lastRecordingDate: profileData.last_recording_date
        };
      } else {
          const { data: { user: authUser } } = await supabase.auth.getUser();
          profileBase.name = authUser?.user_metadata?.name || 'Student';
      }

      const { data: historyData } = await supabase
        .from('history')
        .select('*')
        .eq('user_id', uid)
        .order('created_at', { ascending: true });

      let loadedHistory: AIAnalysis[] = [];
      if (historyData) {
        loadedHistory = historyData.map((h: any) => ({
          transcript: h.transcript,
          score: h.score,
          grammarScore: h.grammar_score,
          pronunciationScore: h.pronunciation_score,
          fluencyScore: h.fluency_score,
          vocabularyScore: h.vocabulary_score,
          feedback: h.feedback || [], 
          tips: h.tips || [], 
          encouragement: h.encouragement,
          timestamp: h.created_at
        }));
        setHistory(loadedHistory);
      }

      const { totalXP, level } = calculateGamification(loadedHistory);

      setUser({
        name: profileBase.name,
        email: email,
        streak: profileBase.streak,
        lastRecordingDate: profileBase.lastRecordingDate,
        xp: totalXP,
        level: level
      });

      if (!isRecoveryMode) {
          setView(AppView.DASHBOARD);
      }
    } catch (e) {
      console.error("Error loading user data", e);
    } finally {
      setIsLoading(false);
    }
  };

  const handleAuth = async (email: string, password: string, name: string, mode: 'LOGIN' | 'SIGNUP') => {
    setIsLoading(true);
    try {
      if (mode === 'SIGNUP') {
        const { data, error } = await supabase.auth.signUp({ 
            email, 
            password,
            options: { data: { name: name } }
        });

        if (error) throw error;

        if (data.user && !data.session) {
            alert("Registration successful! Please check your email to verify your account before logging in.");
            setIsLoading(false);
            return; 
        }

        if (data.user && data.session) {
          await supabase.from('profiles').insert({
            id: data.user.id,
            email: email,
            name: name,
            streak: 0,
            last_recording_date: null
          });
          await loadUserData(data.user.id, email);
        }
      } else {
        const { data, error } = await supabase.auth.signInWithPassword({ email, password });
        if (error) throw error;
        if (data.user) {
          await loadUserData(data.user.id, email);
        }
      }
    } catch (error: any) {
      setIsLoading(false);
      throw error;
    }
  };

  const handleResetPassword = async (email: string) => {
      const redirectUrl = window.location.origin;
      const { error } = await supabase.auth.resetPasswordForEmail(email, {
          redirectTo: redirectUrl,
      });
      if (error) throw error;
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setUserId(null);
    setUser(null);
    setHistory([]);
    setCurrentAnalysis(null);
    setView(AppView.ONBOARDING);
  };

  const handleUpdateProfile = async (newName: string, currentPassword?: string, newPassword?: string) => {
    if (!user || !userId) return;

    try {
      const { error: updateError } = await supabase
        .from('profiles')
        .update({ name: newName })
        .eq('id', userId);

      if (updateError) throw updateError;

      if (newPassword) {
        if (!isRecoveryMode && currentPassword) {
            const { error: verifyError } = await supabase.auth.signInWithPassword({
                email: user.email,
                password: currentPassword
            });
            if (verifyError) throw new Error("Incorrect current password.");
        }
        const { error: pwError } = await supabase.auth.updateUser({ password: newPassword });
        if (pwError) throw pwError;

        if (isRecoveryMode) {
            setIsRecoveryMode(false);
            alert("Password updated successfully! Redirecting to Dashboard.");
            setView(AppView.DASHBOARD);
            return; 
        }
      }

      setUser({ ...user, name: newName });
    } catch (error: any) {
      console.error("Update failed", error);
      throw error; 
    }
  };

  const handleStartRecording = () => {
    setView(AppView.RECORDING);
  };

  // --- ANALYSIS HANDLER (OPTIMIZED) ---
  const handleAnalyze = async (audioBase64: string, duration: number, mimeType: string) => {
    if (!user || !userId) return;

    setIsAnalyzing(true);
    try {
      // 1. Get Analysis from AI
      const analysis = await analyzeAudio(audioBase64, duration, mimeType, language);

      // 2. Prepare Optimistic UI Data
      const today = new Date().toDateString();
      const lastDate = user.lastRecordingDate ? new Date(user.lastRecordingDate).toDateString() : null;
      const isoTimestamp = new Date().toISOString();
      analysis.timestamp = isoTimestamp;

      let newStreak = user.streak;
      if (lastDate !== today) {
          newStreak = user.streak + 1;
      }

      const newHistory = [...history, analysis];
      const { totalXP, level } = calculateGamification(newHistory);

      // 3. UPDATE UI IMMEDIATELY (Do NOT wait for DB)
      // This prevents the "Finalizing..." stall if DB is slow.
      setUser({
          ...user,
          streak: newStreak,
          lastRecordingDate: isoTimestamp,
          xp: totalXP,
          level: level
      });
      setCurrentAnalysis(analysis);
      setHistory(newHistory);

      // UNMOUNT RECORDER NOW
      setView(AppView.ANALYSIS);
      setIsAnalyzing(false);

      // 4. SAVE TO DB IN BACKGROUND (Fire & Forget)
      // We do not await this, so the UI is already responsive.
      (async () => {
          try {
              // Save History
              const { error: histError } = await supabase.from('history').insert({
                user_id: userId,
                transcript: analysis.transcript,
                score: analysis.score,
                grammar_score: analysis.grammarScore,
                pronunciation_score: analysis.pronunciationScore,
                fluency_score: analysis.fluencyScore,
                vocabulary_score: analysis.vocabularyScore,
                feedback: analysis.feedback || [], 
                tips: analysis.tips || [], 
                encouragement: analysis.encouragement,
                created_at: isoTimestamp
              });
              if (histError) console.error("Background Save History Failed:", histError);

              // Update Profile
              const { error: profError } = await supabase.from('profiles').upsert({ 
                  id: userId,
                  name: user.name,
                  email: user.email,
                  streak: newStreak, 
                  last_recording_date: isoTimestamp 
              });
              if (profError) console.error("Background Save Profile Failed:", profError);
          } catch (dbErr) {
              console.error("Background DB Error:", dbErr);
          }
      })();

    } catch (error: any) {
      console.error("Analysis Error in App:", error);
      setIsAnalyzing(false);
      throw error; // Pass back to AudioRecorder to show error
    }
  };

  const handleCloseFeedback = () => {
    setCurrentAnalysis(null);
    setView(AppView.DASHBOARD);
  };

  const handleViewHistory = (analysis: AIAnalysis) => {
    setCurrentAnalysis(analysis);
    setView(AppView.ANALYSIS);
  };

  const handleManualReset = () => {
      localStorage.clear();
      window.location.reload();
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-black flex flex-col items-center justify-center gap-6 p-4 text-center">
        <div className="text-blue-500 animate-pulse text-xl font-serif">Loading Global Voice Club...</div>
        {showResetButton && (
            <div className="animate-fade-in flex flex-col items-center">
                <button 
                    onClick={handleManualReset}
                    className="px-4 py-2 bg-gray-800 border border-gray-600 rounded-lg text-white text-sm"
                >
                    Refresh & Fix
                </button>
            </div>
        )}
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-black text-white font-sans selection:bg-blue-600 selection:text-white overflow-x-hidden w-full flex flex-col">
      <Header 
        user={user} 
        text={text}
        language={language}
        version={UI_VERSION}
        onToggleLanguage={() => setLanguage(l => l === 'en' ? 'zh' : 'en')}
        onLogout={handleLogout} 
        onProfileClick={() => setView(AppView.PROFILE)}
        onLogoClick={() => setView(AppView.DASHBOARD)}
      />
      <main className="w-full max-w-[95%] 2xl:max-w-[1800px] mx-auto px-4 md:px-8 pt-6 pb-12 flex-grow">
        {view === AppView.ONBOARDING && (
          <Onboarding onAuth={handleAuth} onResetPassword={handleResetPassword} text={text} />
        )}
        {view === AppView.DASHBOARD && user && (
          <Dashboard user={user} history={history} onStartRecording={handleStartRecording} onViewHistory={handleViewHistory} text={text} />
        )}
        {view === AppView.PROFILE && user && (
            <Profile user={user} history={history} onUpdateProfile={handleUpdateProfile} onBack={() => setView(AppView.DASHBOARD)} text={text} isRecoveryMode={isRecoveryMode} />
        )}
        {view === AppView.RECORDING && (
          <AudioRecorder onAnalyze={handleAnalyze} isAnalyzing={isAnalyzing} onBack={() => setView(AppView.DASHBOARD)} text={text} />
        )}
        {view === AppView.ANALYSIS && currentAnalysis && user && (
          <FeedbackDisplay analysis={currentAnalysis} userName={user.name} userEmail={user.email} onClose={handleCloseFeedback} text={text} />
        )}
      </main>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type, Schema, HarmCategory, HarmBlockThreshold } from "@google/genai";
import { AIAnalysis, FeedbackItem } from "../types";

// Critical: Check API Key immediately
if (!process.env.API_KEY) {
    console.error("CRITICAL ERROR: API_KEY is missing from environment variables.");
}

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

// --- SCHEMAS ---

const analysisSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    score: { type: Type.NUMBER, description: "Score 0-100" },
    grammarScore: { type: Type.NUMBER, description: "Grammar 0-100" },
    pronunciationScore: { type: Type.NUMBER, description: "Pronun 0-100" },
    fluencyScore: { type: Type.NUMBER, description: "Fluency 0-100" },
    vocabularyScore: { type: Type.NUMBER, description: "Vocab 0-100" },
    feedback: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          original: { type: Type.STRING },
          correction: { type: Type.STRING },
          explanation: { type: Type.STRING },
        },
        required: ["original", "correction", "explanation"]
      }
    },
    tips: { type: Type.ARRAY, items: { type: Type.STRING } },
    encouragement: { type: Type.STRING },
    transcript: { type: Type.STRING }
  },
  required: ["score", "grammarScore", "pronunciationScore", "fluencyScore", "vocabularyScore", "feedback", "tips", "encouragement", "transcript"],
};

// --- HELPERS ---

const generateFallbackAnalysis = (reason: string, partialData?: Partial<AIAnalysis>): AIAnalysis => {
    console.warn("Generating Fallback Analysis. Reason:", reason);

    // Default values if partial data is missing
    const baseScore = partialData?.score !== undefined ? partialData.score : 75;

    // If we have some feedback, use it. Otherwise generate placeholders.
    const feedback = (partialData?.feedback && partialData.feedback.length > 0) 
        ? partialData.feedback 
        : Array(10).fill(null).map((_, i) => ({
            original: i === 0 ? "(Audio processed partially)" : "...",
            correction: i === 0 ? "Connection unstable" : "...",
            explanation: "We recovered as much data as possible, but some details were lost."
        }));

    return {
        score: baseScore, 
        grammarScore: partialData?.grammarScore !== undefined ? partialData.grammarScore : baseScore,
        pronunciationScore: partialData?.pronunciationScore !== undefined ? partialData.pronunciationScore : baseScore,
        fluencyScore: partialData?.fluencyScore !== undefined ? partialData.fluencyScore : baseScore,
        vocabularyScore: partialData?.vocabularyScore !== undefined ? partialData.vocabularyScore : baseScore,
        feedback,
        tips: partialData?.tips && partialData.tips.length > 0 ? partialData.tips : [
            "Ensure you have a stable internet connection.",
            "Try keeping recordings under 3 minutes for faster results.",
            "Speak clearly and close to the microphone.",
            "Reduce background noise.",
            "Practice regularly to improve speed."
        ],
        encouragement: partialData?.encouragement || "Analysis recovered. Keep practicing!",
        transcript: partialData?.transcript || "(Transcript unavailable - Recovery Mode)",
        timestamp: new Date().toISOString()
    };
};

const repairJSON = (jsonStr: string): string => {
    let repaired = jsonStr.trim();
    // 1. Remove trailing commas before closing braces
    repaired = repaired.replace(/,\s*([\]}])/g, '$1');

    // 2. Close open strings if cut off (heuristic: odd count of unescaped quotes)
    // This is risky, but better than a crash.
    const quoteCount = (repaired.match(/(?<!\\)"/g) || []).length;
    if (quoteCount % 2 !== 0) {
        repaired += '"';
    }

    // 3. Balance Brackets/Braces
    const openBraces = (repaired.match(/\{/g) || []).length;
    const closeBraces = (repaired.match(/\}/g) || []).length;
    const openBrackets = (repaired.match(/\[/g) || []).length;
    const closeBrackets = (repaired.match(/\]/g) || []).length;

    if (openBrackets > closeBrackets) repaired += ']'.repeat(openBrackets - closeBrackets);
    if (openBraces > closeBraces) repaired += '}'.repeat(openBraces - closeBraces);

    return repaired;
};

// Improved Regex Extraction to salvage data when JSON fails
const extractViaRegex = (text: string): Partial<AIAnalysis> | null => {
    console.log("Attempting Regex Extraction...");
    try {
        const scoreMatch = text.match(/"score"\s*:\s*(\d+)/);
        const grammarMatch = text.match(/"grammarScore"\s*:\s*(\d+)/);
        const transcriptMatch = text.match(/"transcript"\s*:\s*"([\s\S]*?)(?:"\s*\}|$)/);

        // Attempt to find feedback items (basic)
        // Look for objects containing "original" and "correction"
        const feedbackItems: FeedbackItem[] = [];
        const feedbackRegex = /{\s*"original"\s*:\s*"([^"]+)"\s*,\s*"correction"\s*:\s*"([^"]+)"\s*,\s*"explanation"\s*:\s*"([^"]+)"\s*}/g;
        let match;
        while ((match = feedbackRegex.exec(text)) !== null) {
            feedbackItems.push({
                original: match[1],
                correction: match[2],
                explanation: match[3]
            });
        }

        if (scoreMatch || feedbackItems.length > 0) {
            return {
                score: scoreMatch ? parseInt(scoreMatch[1]) : 70,
                grammarScore: grammarMatch ? parseInt(grammarMatch[1]) : undefined,
                transcript: transcriptMatch ? transcriptMatch[1] : undefined,
                feedback: feedbackItems
            };
        }
    } catch (e) {
        console.warn("Regex extraction failed", e);
    }
    return null;
};

// Validator to ensure we don't return empty "valid" JSON
const validateAnalysis = (data: any): boolean => {
    if (!data || typeof data !== 'object') return false;
    // Must have at least a score OR some feedback to be useful
    if (typeof data.score !== 'number' && (!data.feedback || data.feedback.length === 0)) {
        return false;
    }
    return true;
};

const safeJSONParse = (text: string): any => {
    if (!text) throw new Error("Empty JSON text");

    let clean = text.replace(/```json/g, '').replace(/```/g, '').trim();

    // STRATEGY 1: Direct Parse
    try {
        const result = JSON.parse(clean);
        if (validateAnalysis(result)) {
            console.log("JSON Parse: Success (Direct)");
            return result;
        }
    } catch (e) { /* continue */ }

    // STRATEGY 2: Repair & Parse
    try {
        const repaired = repairJSON(clean);
        const result = JSON.parse(repaired);
        if (validateAnalysis(result)) {
            console.log("JSON Parse: Success (Repaired)");
            return result;
        }
    } catch (e) { /* continue */ }

    // STRATEGY 3: Substring Rescue (if wrapper is broken)
    try {
        const first = clean.indexOf('{');
        const last = clean.lastIndexOf('}');
        if (first !== -1 && last !== -1) {
            const sub = clean.substring(first, last + 1);
            const result = JSON.parse(sub);
             if (validateAnalysis(result)) {
                console.log("JSON Parse: Success (Substring)");
                return result;
            }
        }
    } catch (e) { /* continue */ }

    // STRATEGY 4: Regex Fallback (Last Resort)
    const regexResult = extractViaRegex(text);
    if (regexResult && validateAnalysis(regexResult)) {
        console.log("JSON Parse: Success (Regex Fallback)");
        return regexResult; // Return partial data, generateRequest will fill gaps
    }

    throw new Error("Data Extraction Failed (All Strategies)");
};

const normalizeFeedback = (rawFeedback: any): FeedbackItem[] => {
    const safeList: FeedbackItem[] = Array.isArray(rawFeedback)
        ? rawFeedback
            .map((item: any) => ({
                original: String(item?.original || "").trim(),
                correction: String(item?.correction || "").trim(),
                explanation: String(item?.explanation || "").trim()
            }))
            .filter(item => item.original && item.correction)
        : [];

    const trimmed = safeList.slice(0, 10);

    const paddingPool: FeedbackItem[] = [
        { original: "(Volume)", correction: "Speak louder.", explanation: "Maintain steady volume." },
        { original: "(Pacing)", correction: "Slow down.", explanation: "Rushing causes slurred words." },
        { original: "(Completeness)", correction: "Finish sentences.", explanation: "Avoid trailing off." },
        { original: "(Clarity)", correction: "Enunciate clearly.", explanation: "Vowel sounds were muddy." },
        { original: "(Grammar)", correction: "Check verb tense.", explanation: "Ensure verbs match time." },
        { original: "(Intonation)", correction: "Use rising tone?", explanation: "Pitch was too flat." },
        { original: "(Structure)", correction: "Shorten sentences.", explanation: "Long sentences lose clarity." },
        { original: "(Confidence)", correction: "Project voice.", explanation: "Confidence improves fluency." },
        { original: "(Diction)", correction: "Hit consonants.", explanation: "Endings were soft." },
        { original: "(Flow)", correction: "Use connectors.", explanation: "Link ideas with 'and/but'." }
    ];

    let poolIndex = 0;
    while (trimmed.length < 10) {
        trimmed.push(paddingPool[poolIndex % paddingPool.length]);
        poolIndex++;
    }

    return trimmed;
};

const generateRequest = async (
    modelName: string,
    contents: any,
    schema: Schema,
    timeoutMs: number,
    systemInstruction?: string
): Promise<any> => {
    const controller = new AbortController();

    const timeoutPromise = new Promise((_, reject) => 
        setTimeout(() => {
            controller.abort(); 
            reject(new Error("API_TIMEOUT"));
        }, timeoutMs)
    );

    try {
        const apiPromise = ai.models.generateContent({
            model: modelName,
            contents: contents,
            config: {
                responseMimeType: "application/json",
                responseSchema: schema,
                systemInstruction: systemInstruction,
                maxOutputTokens: 8192, // High limit for long audio
                temperature: 0.2, 
                safetySettings: [
                     { category: HarmCategory.HARM_CATEGORY_HATE_SPEECH, threshold: HarmBlockThreshold.BLOCK_NONE },
                     { category: HarmCategory.HARM_CATEGORY_SEXUALLY_EXPLICIT, threshold: HarmBlockThreshold.BLOCK_NONE },
                     { category: HarmCategory.HARM_CATEGORY_DANGEROUS_CONTENT, threshold: HarmBlockThreshold.BLOCK_NONE },
                     { category: HarmCategory.HARM_CATEGORY_HARASSMENT, threshold: HarmBlockThreshold.BLOCK_NONE }
                ]
            }
        });

        const result: any = await Promise.race([apiPromise, timeoutPromise]);

        let responseText = result?.text;
        const candidate = result?.candidates?.[0];

        if (!responseText && candidate?.content?.parts) {
             responseText = candidate.content.parts.map((p: any) => p.text).join('');
        }

        if (!responseText) throw new Error("EMPTY_RESPONSE");

        // PARSE & VALIDATE
        // safeJSONParse now includes the Regex Fallback strategy internally
        return safeJSONParse(responseText);

    } catch (error: any) {
        if (error.message === 'API_TIMEOUT') throw error;

        console.warn("AI Raw Error:", error);
        throw new Error("API_ERROR");
    }
};

export const analyzeAudio = async (base64Audio: string, duration: number, mimeType: string, language: 'en' | 'zh'): Promise<AIAnalysis> => {

    // --- SLA CONFIGURATION ---
    const SLA_TIMEOUT_MS = 85000; 

    if (!base64Audio || base64Audio.length < 100) throw new Error("Audio is empty.");
    if (base64Audio.length > 15 * 1024 * 1024) throw new Error("File too large (>15MB).");

    let langContext = "Role: English Teacher. Output: JSON. Language: English."; 
    if (language === 'zh') {
        langContext = "Role: ESL Teacher. Output: JSON. Language: Explanations in Traditional Chinese, Corrections in English.";
    }

    // --- OPTIMIZED PROMPT ---
    const promptInstructions = `
    Task: Analyze audio.
    Output JSON object with these keys in this specific order:
    1. score (number)
    2. grammarScore (number)
    3. pronunciationScore (number)
    4. fluencyScore (number)
    5. vocabularyScore (number)
    6. feedback (array of objects: original, correction, explanation)
    7. tips (array of strings)
    8. encouragement (string)
    9. transcript (string) -- Put transcript LAST.
    `;

    const logicPromise = async () => {
        // Attempt generation
        const result = await generateRequest(
            'gemini-2.5-flash', 
            {
                parts: [
                    { inlineData: { data: base64Audio, mimeType: mimeType } },
                    { text: promptInstructions }
                ]
            },
            analysisSchema,
            SLA_TIMEOUT_MS - 2000, 
            langContext
        );

        // MERGE LOGIC: Even if 'result' is partial (from regex), we fill the gaps here
        // instead of throwing an error.

        const baseScore = result.score || 70;

        return {
            score: baseScore,
            grammarScore: result.grammarScore || baseScore,
            pronunciationScore: result.pronunciationScore || baseScore,
            fluencyScore: result.fluencyScore || baseScore,
            vocabularyScore: result.vocabularyScore || baseScore,
            feedback: normalizeFeedback(result.feedback),
            tips: Array.isArray(result.tips) ? result.tips.slice(0, 5) : [],
            encouragement: result.encouragement || "Great job practicing!",
            transcript: result.transcript || "(Transcript unavailable)",
            timestamp: new Date().toISOString()
        } as AIAnalysis;
    };

    const timeoutPromise = new Promise<AIAnalysis>((resolve) => {
        setTimeout(() => {
            resolve(generateFallbackAnalysis("Timeout (85s Limit Reached)"));
        }, SLA_TIMEOUT_MS);
    });

    try {
        console.log(`Starting Analysis. Size: ${(base64Audio.length/1024/1024).toFixed(2)}MB`);
        return await Promise.race([logicPromise(), timeoutPromise]);
    } catch (error: any) {
        console.error("Analysis Exception:", error);

        // Only return generic fallback if EVERYTHING failed (including regex rescue)
        return generateFallbackAnalysis(error.message || "Unknown Error");
    }
};

import React, { useState, useEffect } from 'react';
import { UserProfile, AIAnalysis, AppView, Language } from './types';
import Header from './components/Header';
import Onboarding from './components/Onboarding';
import AudioRecorder from './components/AudioRecorder';
import FeedbackDisplay from './components/FeedbackDisplay';
import Dashboard from './components/Dashboard';
import Profile from './components/Profile';
import { analyzeAudio } from './services/geminiService';
import { supabase } from './services/supabaseClient';
import { translations } from './utils/translations';
import { checkAndEnforceVersion } from './utils/versionManager';

// We now read the version from the manifest via the manager, 
// but we keep this for the UI display.
// IMPORTANT: Update 'version.json' when you update this!
const UI_VERSION = '1.0.54'; 

const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [userId, setUserId] = useState<string | null>(null); // Supabase Auth ID
  const [view, setView] = useState<AppView>(AppView.ONBOARDING);
  const [history, setHistory] = useState<AIAnalysis[]>([]);
  const [currentAnalysis, setCurrentAnalysis] = useState<AIAnalysis | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [showResetButton, setShowResetButton] = useState(false); // Fail-safe button

  // Recovery Mode State (For Password Reset)
  const [isRecoveryMode, setIsRecoveryMode] = useState(false);

  // Language State - Default to Traditional Chinese ('zh')
  const [language, setLanguage] = useState<Language>('zh');
  const text = translations[language];

  // Initialize Session
  useEffect(() => {

    // --- STEP 1: VERSION CHECK ---
    checkAndEnforceVersion();

    // Timer to show the "Reset" button if loading takes too long
    const resetTimer = setTimeout(() => {
        if (isLoading) setShowResetButton(true);
    }, 4000);

    const initApp = async () => {
        // SAFETY TIMEOUT: Force loading to stop after 7 seconds max
        const timeoutPromise = new Promise((_, reject) => 
            setTimeout(() => reject(new Error("Initialization timed out")), 7000)
        );

        const sessionPromise = async () => {
            const { data, error } = await supabase.auth.getSession();
            if (error) throw error;

            if (data?.session) {
                await loadUserData(data.session.user.id, data.session.user.email || '');
            } else {
                setView(AppView.ONBOARDING);
            }
        };

        try {
            await Promise.race([sessionPromise(), timeoutPromise]);
        } catch (error) {
            console.warn("App Initialization fallback:", error);
            if (!userId) setView(AppView.ONBOARDING);
        } finally {
            setIsLoading(false);
            clearTimeout(resetTimer);
        }
    };

    initApp();

    const { data: authListener } = supabase.auth.onAuthStateChange(async (event, session) => {
        if (event === 'PASSWORD_RECOVERY') {
            setIsRecoveryMode(true);
            setView(AppView.PROFILE); 
            setIsLoading(false);
        } else if (event === 'SIGNED_IN' && session) {
             if (!userId) {
                await loadUserData(session.user.id, session.user.email || '');
             }
        } else if (event === 'SIGNED_OUT') {
            setUser(null);
            setUserId(null);
            setHistory([]);
            setCurrentAnalysis(null);
            setView(AppView.ONBOARDING);
            setIsRecoveryMode(false);
            setIsLoading(false);
        }
    });

    return () => {
        authListener.subscription.unsubscribe();
        clearTimeout(resetTimer);
    };
  }, []);

  // Helper to calculate XP/Level from history list
  const calculateGamification = (historyList: AIAnalysis[]) => {
      let totalXP = 0;
      historyList.forEach(item => {
          const wordCount = item.transcript ? item.transcript.split(' ').length : 0;
          totalXP += Math.round(item.score + (wordCount * 0.5));
      });

      let level = 1;
      let costForNext = 300;
      let remainingXP = totalXP;

      while (remainingXP >= costForNext) {
          remainingXP -= costForNext;
          level++;
          costForNext += 500;
          if (costForNext > 3000) costForNext = 3000;
      }

      return { totalXP, level };
  };

  const loadUserData = async (uid: string, email: string) => {
    try {
      setUserId(uid);

      let profileBase = { name: 'Student', streak: 0, lastRecordingDate: null as string | null };

      const { data: profileData } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', uid)
        .single();

      if (profileData) {
        profileBase = {
            name: profileData.name,
            streak: profileData.streak || 0,
            lastRecordingDate: profileData.last_recording_date
        };
      } else {
          const { data: { user: authUser } } = await supabase.auth.getUser();
          profileBase.name = authUser?.user_metadata?.name || 'Student';
      }

      const { data: historyData } = await supabase
        .from('history')
        .select('*')
        .eq('user_id', uid)
        .order('created_at', { ascending: true });

      let loadedHistory: AIAnalysis[] = [];
      if (historyData) {
        loadedHistory = historyData.map((h: any) => ({
          transcript: h.transcript,
          score: h.score,
          grammarScore: h.grammar_score,
          pronunciationScore: h.pronunciation_score,
          fluencyScore: h.fluency_score,
          vocabularyScore: h.vocabulary_score,
          feedback: h.feedback || [], 
          tips: h.tips || [], 
          encouragement: h.encouragement,
          timestamp: h.created_at
        }));
        setHistory(loadedHistory);
      }

      const { totalXP, level } = calculateGamification(loadedHistory);

      setUser({
        name: profileBase.name,
        email: email,
        streak: profileBase.streak,
        lastRecordingDate: profileBase.lastRecordingDate,
        xp: totalXP,
        level: level
      });

      if (!isRecoveryMode) {
          setView(AppView.DASHBOARD);
      }
    } catch (e) {
      console.error("Error loading user data", e);
    } finally {
      setIsLoading(false);
    }
  };

  const handleAuth = async (email: string, password: string, name: string, mode: 'LOGIN' | 'SIGNUP') => {
    setIsLoading(true);
    try {
      if (mode === 'SIGNUP') {
        const { data, error } = await supabase.auth.signUp({ 
            email, 
            password,
            options: { data: { name: name } }
        });

        if (error) throw error;

        if (data.user && !data.session) {
            alert("Registration successful! Please check your email to verify your account before logging in.");
            setIsLoading(false);
            return; 
        }

        if (data.user && data.session) {
          await supabase.from('profiles').insert({
            id: data.user.id,
            email: email,
            name: name,
            streak: 0,
            last_recording_date: null
          });
          await loadUserData(data.user.id, email);
        }
      } else {
        const { data, error } = await supabase.auth.signInWithPassword({ email, password });
        if (error) throw error;
        if (data.user) {
          await loadUserData(data.user.id, email);
        }
      }
    } catch (error: any) {
      setIsLoading(false);
      throw error;
    }
  };

  const handleResetPassword = async (email: string) => {
      const redirectUrl = window.location.origin;
      const { error } = await supabase.auth.resetPasswordForEmail(email, {
          redirectTo: redirectUrl,
      });
      if (error) throw error;
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setUserId(null);
    setUser(null);
    setHistory([]);
    setCurrentAnalysis(null);
    setView(AppView.ONBOARDING);
  };

  const handleUpdateProfile = async (newName: string, currentPassword?: string, newPassword?: string) => {
    if (!user || !userId) return;

    try {
      const { error: updateError } = await supabase
        .from('profiles')
        .update({ name: newName })
        .eq('id', userId);

      if (updateError) throw updateError;

      if (newPassword) {
        if (!isRecoveryMode && currentPassword) {
            const { error: verifyError } = await supabase.auth.signInWithPassword({
                email: user.email,
                password: currentPassword
            });
            if (verifyError) throw new Error("Incorrect current password.");
        }
        const { error: pwError } = await supabase.auth.updateUser({ password: newPassword });
        if (pwError) throw pwError;

        if (isRecoveryMode) {
            setIsRecoveryMode(false);
            alert("Password updated successfully! Redirecting to Dashboard.");
            setView(AppView.DASHBOARD);
            return; 
        }
      }

      setUser({ ...user, name: newName });
    } catch (error: any) {
      console.error("Update failed", error);
      throw error; 
    }
  };

  const handleStartRecording = () => {
    setView(AppView.RECORDING);
  };

  // --- ANALYSIS HANDLER (OPTIMIZED) ---
  const handleAnalyze = async (audioBase64: string, duration: number, mimeType: string) => {
    if (!user || !userId) return;

    setIsAnalyzing(true);
    try {
      // 1. Get Analysis from AI
      const analysis = await analyzeAudio(audioBase64, duration, mimeType, language);

      // 2. Prepare Optimistic UI Data
      const today = new Date().toDateString();
      const lastDate = user.lastRecordingDate ? new Date(user.lastRecordingDate).toDateString() : null;
      const isoTimestamp = new Date().toISOString();
      analysis.timestamp = isoTimestamp;

      let newStreak = user.streak;
      if (lastDate !== today) {
          newStreak = user.streak + 1;
      }

      const newHistory = [...history, analysis];
      const { totalXP, level } = calculateGamification(newHistory);

      // 3. UPDATE UI IMMEDIATELY (Do NOT wait for DB)
      // This prevents the "Finalizing..." stall if DB is slow.
      setUser({
          ...user,
          streak: newStreak,
          lastRecordingDate: isoTimestamp,
          xp: totalXP,
          level: level
      });
      setCurrentAnalysis(analysis);
      setHistory(newHistory);

      // UNMOUNT RECORDER NOW
      setView(AppView.ANALYSIS);
      setIsAnalyzing(false);

      // 4. SAVE TO DB IN BACKGROUND (Fire & Forget)
      // We do not await this, so the UI is already responsive.
      (async () => {
          try {
              // Save History
              const { error: histError } = await supabase.from('history').insert({
                user_id: userId,
                transcript: analysis.transcript,
                score: analysis.score,
                grammar_score: analysis.grammarScore,
                pronunciation_score: analysis.pronunciationScore,
                fluency_score: analysis.fluencyScore,
                vocabulary_score: analysis.vocabularyScore,
                feedback: analysis.feedback || [], 
                tips: analysis.tips || [], 
                encouragement: analysis.encouragement,
                created_at: isoTimestamp
              });
              if (histError) console.error("Background Save History Failed:", histError);

              // Update Profile
              const { error: profError } = await supabase.from('profiles').upsert({ 
                  id: userId,
                  name: user.name,
                  email: user.email,
                  streak: newStreak, 
                  last_recording_date: isoTimestamp 
              });
              if (profError) console.error("Background Save Profile Failed:", profError);
          } catch (dbErr) {
              console.error("Background DB Error:", dbErr);
          }
      })();

    } catch (error: any) {
      console.error("Analysis Error in App:", error);
      setIsAnalyzing(false);
      throw error; // Pass back to AudioRecorder to show error
    }
  };

  const handleCloseFeedback = () => {
    setCurrentAnalysis(null);
    setView(AppView.DASHBOARD);
  };

  const handleViewHistory = (analysis: AIAnalysis) => {
    setCurrentAnalysis(analysis);
    setView(AppView.ANALYSIS);
  };

  const handleManualReset = () => {
      localStorage.clear();
      window.location.reload();
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-black flex flex-col items-center justify-center gap-6 p-4 text-center">
        <div className="text-blue-500 animate-pulse text-xl font-serif">Loading Global Voice Club...</div>
        {showResetButton && (
            <div className="animate-fade-in flex flex-col items-center">
                <button 
                    onClick={handleManualReset}
                    className="px-4 py-2 bg-gray-800 border border-gray-600 rounded-lg text-white text-sm"
                >
                    Refresh & Fix
                </button>
            </div>
        )}
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-black text-white font-sans selection:bg-blue-600 selection:text-white overflow-x-hidden w-full flex flex-col">
      <Header 
        user={user} 
        text={text}
        language={language}
        version={UI_VERSION}
        onToggleLanguage={() => setLanguage(l => l === 'en' ? 'zh' : 'en')}
        onLogout={handleLogout} 
        onProfileClick={() => setView(AppView.PROFILE)}
        onLogoClick={() => setView(AppView.DASHBOARD)}
      />
      <main className="w-full max-w-[95%] 2xl:max-w-[1800px] mx-auto px-4 md:px-8 pt-6 pb-12 flex-grow">
        {view === AppView.ONBOARDING && (
          <Onboarding onAuth={handleAuth} onResetPassword={handleResetPassword} text={text} />
        )}
        {view === AppView.DASHBOARD && user && (
          <Dashboard user={user} history={history} onStartRecording={handleStartRecording} onViewHistory={handleViewHistory} text={text} />
        )}
        {view === AppView.PROFILE && user && (
            <Profile user={user} history={history} onUpdateProfile={handleUpdateProfile} onBack={() => setView(AppView.DASHBOARD)} text={text} isRecoveryMode={isRecoveryMode} />
        )}
        {view === AppView.RECORDING && (
          <AudioRecorder onAnalyze={handleAnalyze} isAnalyzing={isAnalyzing} onBack={() => setView(AppView.DASHBOARD)} text={text} />
        )}
        {view === AppView.ANALYSIS && currentAnalysis && user && (
          <FeedbackDisplay analysis={currentAnalysis} userName={user.name} userEmail={user.email} onClose={handleCloseFeedback} text={text} />
        )}
      </main>
    </div>
  );
};

